INSERT INTO `sys_oper_log` VALUES (444, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:22:32\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一个数字寻址式火警探测和报警系统。[ID:0] 它专门设计用于在船舶和海洋石油平台等高风险环境中提供火灾探测和安全报警功能。[ID:1] T2000系统的主要特点包括：\\n\\n- 高度可靠的火警探测技术；\\n- 支持多个回路和区域，可容纳大量探测点；\\n- 集成电源单元，确保系统在断电情况下也能继续工作；\\n- 液晶显示器和控制键，方便操作者监控和控制系统状态；\\n- 多级用户权限，以保障系统的安全性和操作的正确性；\\n- 事件记录和打印功能，便于事后分析和记录；\\n- 满足国际标准和船级社的要求，如欧洲EN54、SOLAS等。\\n\\nT2000系统的功能涵盖了火警监测、报警、事件处理、系统维护等多个方面，旨在为用户提供一个全面、高效的安全解决方案。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000的具体功能或操作有进一步的问题，请告知，我会尽力提供帮助。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:22:32\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一个数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它专门设计用于在船舶和海洋石油平台等高风险环境中提供火灾探测和安全报警功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" T2000系统的主要特点包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 高度可靠的火警探测技术；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 支持多个回路和区域，可容纳大量探测点；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 集成电源单元，确保系统在断电情况下也能继续工作；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 液晶显示器和控制键，方便操作者监控和控制系统状态；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多级用户权限，以保障系统的安全性和操作的正确性；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录和打印功能，便于事后分析和记录；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 满足国际标准和船级社的要求，如欧洲EN54、SOLAS等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000系统的功能涵盖了火警监测、报警、事件处理、系统维护等多个方面，旨在为用户提供一个全面、高效的安全解决方案。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 如果您对T2000的具体功能或操作有进一步的问题，请告知，我会尽力提供帮助。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T200', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'reference\' at row 1\r\n### The error may exist in file [E:\\JAVA\\bj\\gaisoft-aftersales\\target\\classes\\mapper\\kb\\KbChatMapper.xml]\r\n### The error may involve com.gaisoft.kb.mapper.KbChatMapper.insertKbChat-Inline\r\n### The error occurred while setting parameters\r\n### SQL: insert into kb_chat          ( message_id,             chat_id,             role,             session_id,             content,             package_content,             reference,             create_by,             create_time )           values ( ?,             ?,             ?,             ?,             ?,             ?,             ?,             ?,             ? )\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'reference\' at row 1\n; Data truncation: Data too long for column \'reference\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'reference\' at row 1', '2025-07-01 02:22:30', 7710);
INSERT INTO `sys_oper_log` VALUES (445, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。[ID:0] [ID:1] 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\n\\n- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\n- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\n- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\n- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\n- 事件记录：具备事件记录功能，方便用户分析和审查。\\n- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\n\\nT2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000的具体功能或应用有更详细的问题，请继续提问。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录：具备事件记录功能，方便用户分析和审查。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 如果您对T2000的具体功能或应用有更详细的问题，请继续提问。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-07-01 02:23:58', 160);
INSERT INTO `sys_oper_log` VALUES (446, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:28:03\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警探测和报警系统具备以下功能：\\n\\n1. 火警探测：实时监测并识别潜在的火灾风险，发出及时的火警警报。\\n2. 事件记录：记录所有的火警事件、操作日志和系统状态变化，便于事后分析和审查。\\n3. 用户界面：提供液晶显示器和操作键，方便用户查看系统状态、进行操作和系统设置。\\n4. 多级权限：设置不同的用户级别，以确保只有授权人员可以访问和操作系统。\\n5. 报警控制：允许用户进行报警消声、系统复位等控制操作。\\n6. 时间/日期设置：设置系统的时间、日期，以及调整夏令时/冬令时。\\n7. 系统测试：执行系统测试，包括蜂鸣器、灯和显示器的测试。\\n8. 维护和保养：提供系统维护功能，如测试蓄电池、查看火警总数等。\\n9. 打印和输出：支持事件记录的打印和状态数据的输出。\\n10. 网络集成：与其他安全设备（如复示器、打印机）进行网络集成。\\n\\nT2000系统适用于对安全要求较高的环境，如船舶、海洋石油平台等，并且满足国际标准和船级社的要求。[ID:0] [ID:1] [ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您需要了解更多关于T2000的功能或操作细节，请提出具体问题。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:28:03\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统具备以下功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 火警探测：实时监测并识别潜在的火灾风险，发出及时的火警警报。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 事件记录：记录所有的火警事件、操作日志和系统状态变化，便于事后分析和审查。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 用户界面：提供液晶显示器和操作键，方便用户查看系统状态、进行操作和系统设置。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多级权限：设置不同的用户级别，以确保只有授权人员可以访问和操作系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 报警控制：允许用户进行报警消声、系统复位等控制操作。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 时间/日期设置：设置系统的时间、日期，以及调整夏令时/冬令时。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 系统测试：执行系统测试，包括蜂鸣器、灯和显示器的测试。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"8. 维护和保养：提供系统维护功能，如测试蓄电池、查看火警总数等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"9. 打印和输出：支持事件记录的打印和状态数据的输出。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"10. 网络集成：与其他安全设备（如复示器、打印机）进行网络集成。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000系统适用于对安全要求较高的环境，如船舶、海洋石油平台等，并且满足国际标准和船级社的要求。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:28:03\",\"id\":24,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警探测和报警系统具备以下功能：\\n\\n1. 火警探测：实时监测并识别潜在的火灾风险，发出及时的火警警报。\\n2. 事件记录：记录所有的火警事件、操作日志和系统状态变化，便于事后分析和审查。\\n3. 用户界面：提供液晶显示器和操作键，方便用户查看系统状态、进行操作和系统设置。\\n4. 多级权限：设置不同的用户级别，以确保只有授权人员可以访问和操作系统。\\n5. 报警控制：允许用户进行报警消声、系统复位等控制操作。\\n6. 时间/日期设置：设置系统的时间、日期，以及调整夏令时/冬令时。\\n7. 系统测试：执行系统测试，包括蜂鸣器、灯和显示器的测试。\\n8. 维护和保养：提供系统维护功能，如测试蓄电池、查看火警总数等。\\n9. 打印和输出：支持事件记录的打印和状态数据的输出。\\n10. 网络集成：与其他安全设备（如复示器、打印机）进行网络集成。\\n\\nT2000系统适用于对安全要求较高的环境，如船舶、海洋石油平台等，并且满足国际标准和船级社的要求。[ID:0] [ID:1] [ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您需要了解更多关于T2000的功能或操作细节，请提出具体问题。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:28:03\",\"id\":25,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统具备以下功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 火警探测：实时监测并识别潜在的火灾风险，发出及时的火警警报。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 事件记录：记录所有的火警事件、操作日志和系统状态变化，便于事后分析和审查。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 用户界面：提供液晶显示器和操作键，方便用户查看系统状态、进行操作和系统设置。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多级权限：设置不同的用户级别，以确保只有授权人员可以访问和操作系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 报警控制：允许用户进行报警消声、系统复位等控制操作。\\\"}],[{\\\"type\\\"