INSERT INTO `sys_oper_log` VALUES (447, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 11:19:15\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统，它使用数字寻址技术来监测和报警火灾情况。[ID:0] 这种系统通常用于需要高安全标准的场所，如船舶和海洋石油平台，因为它能够满足严格的国际标准和船级社的要求，如欧洲EN54和SOLAS标准。[ID:1]\\n\\nT2000系统的主要功能包括：\\n\\n- 火警探测和报警；\\n- 事件记录和日志管理；\\n- 系统状态监控；\\n- 多级用户权限管理；\\n- 报警控制，如消声和复位；\\n- 时间和日期设置；\\n- 系统测试和维护；\\n- 数据打印和输出；\\n- 网络集成能力。\\n\\nT2000系统的设计旨在提供可靠、易于操作和维护的安全解决方案，以保护人员和资产安全。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000系统有更具体的问题或需要了解更多信息，请告知，我会尽力提供帮助。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 11:19:15\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统，它使用数字寻址技术来监测和报警火灾情况。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 这种系统通常用于需要高安全标准的场所，如船舶和海洋石油平台，因为它能够满足严格的国际标准和船级社的要求，如欧洲EN54和SOLAS标准。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000系统的主要功能包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 火警探测和报警；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录和日志管理；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 系统状态监控；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多级用户权限管理；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 报警控制，如消声和复位；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 时间和日期设置；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 系统测试和维护；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 数据打印和输出；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 网络集成能力。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000系统的设计旨在提供可靠、易于操作和维护的安全解决方案，以保护人员和资产安全。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 如果您对T2000系统有更具体的问题或需要了解更多信息，请告知，我会尽力提供帮助。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 09:19:14\",\"id\":19,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:22:32\",\"id\":21,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"id\":22,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。[ID:0] [ID:1] 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\n\\n- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\n- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\n- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\n- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\n- 事件记录：具备事件记录功能，方便用户分析和审查。\\n- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\n\\nT2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000的具体功能或应用有更详细的问题，请继续提问。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"id\":23,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录：具备事件记录功能，方便用户分析和审查。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。\\\"},{\\\"type\\\":', 0, NULL, '2025-07-01 03:19:13', 256);
INSERT INTO `sys_oper_log` VALUES (448, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好 T2000能做什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 11:25:00\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！T2000火警探测和报警系统能够执行以下任务：\\n\\n1. **火警探测**：它能够实时监测并识别火灾风险，及时发出火警警报。\\n2. **事件记录**：系统会自动记录所有的火警事件、操作日志和系统状态变化，以便进行后续的分析和审查。\\n3. **状态监控**：通过液晶显示器，操作者可以实时查看系统状态和事件信息。\\n4. **用户权限管理**：系统设置了多级用户权限，确保只有授权人员可以执行特定的操作。\\n5. **报警控制**：操作者可以进行报警消声、系统复位等控制操作。\\n6. **时间和日期设置**：系统允许设置和调整当前的时间、日期，以及夏令时/冬令时。\\n7. **测试和维护**：系统提供了测试蜂鸣器、灯和显示器等功能，以及维护请求和蓄电池测试等。\\n8. **数据打印和输出**：支持事件记录的打印和状态数据的输出。\\n9. **网络集成**：T2000可以与其他安全设备（如复示器、打印机）进行网络集成，以增强系统的功能和信息共享。\\n\\nT2000系统适用于对安全性有高要求的场所，如船舶、海洋石油平台等，并且符合国际标准和船级社的要求。[ID:0] [ID:1] [ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您需要了解更多关于T2000的功能或操作细节，请随时提问。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 11:25:00\",\"messageId\":\"\",\"packageContent\":\"[]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"2ed00e236499be93\\\",\\\"content\\\":\\\"2.7.3 打印机 打印机的操作请参照打印机的随机操作手册。3. 控制器功能如上所述，T2000 控制器已经集成了所有必须的功能，包括：让操作者游览事件记录、设定日期和时间等，但不是所有的操作者都可以操作所有的功能，T2000 控制器将操作功能分成了不同的级别，操作者根据自己的级别登录后才可以操作允许操作的功能。3.1 登录级别 T2000控制器的登录级别分为：●客户操作员1到7，密码为4位数字；●客户经理1，密码为5 位数字；●客户经理2，密码为6 位数字；●工程师，密码为7 位数字；●总工程师，密码为8 位数字。T2000 控制器最多可以设置99 个不同的用户密码，其中由于工程师级和总工程师级的功能可以改变系统的设置，不允许一般操作者使用。注：T2000 控制器前面板上的钥匙处在“I”位置就是客户操作员1登录级别，该级别的登录不需要密码。T2000控制器的功能菜单见下：主菜单（MAIN MENU）确认事件（Accept Events）查看状况（View Status）隔离/解除隔离（Isolate/De-isolate）时间/日期（Time/Date）设置时间/日期（Set Time/Date）夏令时/冬令时（Summer/Winter）事件记录（Event Log）查看事件（View Event Log）打印事件记录（Print Event Log）过滤器（Filter）查看/打印状态（View/Print Status）回路点隔离（Points Isolated）回路点没有测试/故障（Points Untested/Failed）回路点实测值（Point Values）查看故障（View Faults）计算回路点总数（Loop Point Counter）\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac120006\\\",\\\"image_id\\\":\\\"9bd2b88a554d11f099d20242ac12000', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 09:19:14\",\"id\":19,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:22:32\",\"id\":21,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"id\":22,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。[ID:0] [ID:1] 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\n\\n- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\n- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\n- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\n- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\n- 事件记录：具备事件记录功能，方便用户分析和审查。\\n- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\n\\nT2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000的具体功能或应用有更详细的问题，请继续提问。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"id\":23,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录：具备事件记录功能，方便用户分析和审查。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。\\\"},{\\\"type\\\":', 0, NULL, '2025-07-01 03:24:58', 142);
INSERT INTO `sys_oper_log` VALUES (449, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好T2000能干什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 11:25:41\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！T2000火警探测和报警系统可以执行以下功能：\\n\\n1. **火警监测**：持续监测环境中的火警信号，一旦检测到火灾迹象，立即发出报警。\\n2. **事件记录**：记录所有火警事件、操作日志和系统状态变化，便于事后分析。\\n3. **用户界面**：提供直观的用户界面，包括液晶显示器和控制键，方便操作者查看系统状态和进行控制操作。\\n4. **权限管理**：设有不同级别的用户权限，以确保只有授权人员可以访问和操作系统的特定功能。\\n5. **报警控制**：允许操作者进行报警消声、系统复位等操作，以控制火警响应。\\n6. **时间和日期设置**：提供时间和日期设置功能，包括夏令时/冬令时的调整。\\n7. **系统测试**：可以进行蜂鸣器、灯和显示器的测试，以确保系统正常运行。\\n8. **维护和保养**：提供系统维护功能，如测试蓄电池、查看火警总数等。\\n9. **数据输出**：支持事件记录的打印和系统状态数据的输出。\\n10. **网络集成**：能够与其他安全设备（如复示器、打印机）进行网络集成，以扩展系统功能。\\n\\nT2000系统适用于对安全性有严格要求的场所，如船舶、海洋石油平台等，并且满足国际标准和船级社的要求。[ID:0] [ID:1] [ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000的具体功能或操作有疑问，欢迎继续提问。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 11:25:41\",\"messageId\":\"\",\"packageContent\":\"[]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"2ed00e236499be93\\\",\\\"content\\\":\\\"2.7.3 打印机 打印机的操作请参照打印机的随机操作手册。3. 控制器功能如上所述，T2000 控制器已经集成了所有必须的功能，包括：让操作者游览事件记录、设定日期和时间等，但不是所有的操作者都可以操作所有的功能，T2000 控制器将操作功能分成了不同的级别，操作者根据自己的级别登录后才可以操作允许操作的功能。3.1 登录级别 T2000控制器的登录级别分为：●客户操作员1到7，密码为4位数字；●客户经理1，密码为5 位数字；●客户经理2，密码为6 位数字；●工程师，密码为7 位数字；●总工程师，密码为8 位数字。T2000 控制器最多可以设置99 个不同的用户密码，其中由于工程师级和总工程师级的功能可以改变系统的设置，不允许一般操作者使用。注：T2000 控制器前面板上的钥匙处在“I”位置就是客户操作员1登录级别，该级别的登录不需要密码。T2000控制器的功能菜单见下：主菜单（MAIN MENU）确认事件（Accept Events）查看状况（View Status）隔离/解除隔离（Isolate/De-isolate）时间/日期（Time/Date）设置时间/日期（Set Time/Date）夏令时/冬令时（Summer/Winter）事件记录（Event Log）查看事件（View Event Log）打印事件记录（Print Event Log）过滤器（Filter）查看/打印状态（View/Print Status）回路点隔离（Points Isolated）回路点没有测试/故障（Points Untested/Failed）回路点实测值（Point Values）查看故障（View Faults）计算回路点总数（Loop Point Counter）\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac120006\\\",\\\"image_id\\\":\\', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 09:19:14\",\"id\":19,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:22:32\",\"id\":21,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"id\":22,\"params\":{},\"role\":\"user\",\"sessionId\":\"64d7a60c561911f0a0910242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。[ID:0] [ID:1] 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\n\\n- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\n- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\n- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\n- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\n- 事件记录：具备事件记录功能，方便用户分析和审查。\\n- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\n\\nT2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7] 如果您对T2000的具体功能或应用有更详细的问题，请继续提问。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 10:24:00\",\"id\":23,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统，它采用了数字寻址技术，用于在船舶、海洋石油平台等对安全性有高要求的场合进行火灾的监测和报警。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统由火警控制器、探测器、报警器等组件构成，具备以下特点：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 高可靠性：采用泰科公司的MX TechnologyTM技术，确保系统稳定可靠。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多回路和区域：支持多个回路和区域，可容纳大量探测点，满足不同场地的需求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 集成电源：集成电源单元，支持交流电和蓄电池供电，确保系统在断电情况下也能运行。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 用户权限：设有多个用户级别，限制对系统功能的访问，保证操作安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录：具备事件记录功能，方便用户分析和审查。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 国际标准：符合欧洲EN54、SOLAS等国际标准和船级社的要求。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统的主要作用是及时发现火灾，发出警报，并提供必要的控制功能，以帮助用户快速响应和处理火警事件。\\\"},{\\\"type\\\":', 0, NULL, '2025-07-01 03:25:39', 139);
