INSERT INTO `sys_oper_log` VALUES (452, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/session', '192.168.1.101', '内网IP', '{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:12:49\",\"id\":31,\"params\":{},\"sessionId\":\"06f99f38563a11f0a72b0242ac120006\",\"sessionName\":\"你好T2000能做什么\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:12:49\",\"id\":31,\"params\":{},\"sessionId\":\"06f99f38563a11f0a72b0242ac120006\",\"sessionName\":\"你好T2000能做什么\"}}', 0, NULL, '2025-07-01 05:12:47', 251);
INSERT INTO `sys_oper_log` VALUES (453, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好T2000能做什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:13:04\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"06f99f38563a11f0a72b0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一款火警探测和报警系统控制器，集成了多种功能。它能够进行事件记录、设定日期和时间、隔离和解除隔离等操作。T2000控制器的功能分为不同的级别，操作者根据自己的级别登录后才可以操作对应的功能。功能菜单包括但不限于以下内容：确认事件、查看状况、隔离/解除隔离、时间/日期设置、查看和打印事件记录、查看和打印状态、回路点隔离、回路点实测值查看等[ID:0]。\\n\\n此外，T2000系统还具备以下性能和功能：\\n- 集成电源单元，可为非寻址设备接口模块、非寻址报警器和蜂鸣器、门释放装置和复示器供电[ID:2]；\\n- 支持多级别登录，包括客户操作员、客户经理、工程师和总工程师等[ID:0]；\\n- 可以组成网络，通过Peer-to-peer的通讯方式实现无缝连接和信息共享[ID:7]；\\n- 事件记录最多可以记录3000条事件，这些记录可以被查看、选择和打印[ID:7]；\\n- 提供了连续监控所有探头、手报按钮和输入电路状况的功能，并使用先进技术处理信息以降低或消除虚假警报的发生[ID:7]。\\n\\n以上是T2000火警控制器的主要功能概述。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:13:04\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一款火警探测和报警系统控制器，集成了多种功能。它能够进行事件记录、设定日期和时间、隔离和解除隔离等操作。T2000控制器的功能分为不同的级别，操作者根据自己的级别登录后才可以操作对应的功能。功能菜单包括但不限于以下内容：确认事件、查看状况、隔离/解除隔离、时间/日期设置、查看和打印事件记录、查看和打印状态、回路点隔离、回路点实测值查看等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"此外，T2000系统还具备以下性能和功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 集成电源单元，可为非寻址设备接口模块、非寻址报警器和蜂鸣器、门释放装置和复示器供电\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 支持多级别登录，包括客户操作员、客户经理、工程师和总工程师等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 可以组成网络，通过Peer-to-peer的通讯方式实现无缝连接和信息共享\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录最多可以记录3000条事件，这些记录可以被查看、选择和打印\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"；\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 提供了连续监控所有探头、手报按钮和输入电路状况的功能，并使用先进技术处理信息以降低或消除虚假警报的发生\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以上是T2000火警控制器的主要功能概述。\\\"}]]\",\"params\":{},\"reference', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:12:50\",\"id\":32,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"06f99f38563a11f0a72b0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好T2000能做什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:13:04\",\"id\":33,\"params\":{},\"role\":\"user\",\"sessionId\":\"06f99f38563a11f0a72b0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一款火警探测和报警系统控制器，集成了多种功能。它能够进行事件记录、设定日期和时间、隔离和解除隔离等操作。T2000控制器的功能分为不同的级别，操作者根据自己的级别登录后才可以操作对应的功能。功能菜单包括但不限于以下内容：确认事件、查看状况、隔离/解除隔离、时间/日期设置、查看和打印事件记录、查看和打印状态、回路点隔离、回路点实测值查看等[ID:0]。\\n\\n此外，T2000系统还具备以下性能和功能：\\n- 集成电源单元，可为非寻址设备接口模块、非寻址报警器和蜂鸣器、门释放装置和复示器供电[ID:2]；\\n- 支持多级别登录，包括客户操作员、客户经理、工程师和总工程师等[ID:0]；\\n- 可以组成网络，通过Peer-to-peer的通讯方式实现无缝连接和信息共享[ID:7]；\\n- 事件记录最多可以记录3000条事件，这些记录可以被查看、选择和打印[ID:7]；\\n- 提供了连续监控所有探头、手报按钮和输入电路状况的功能，并使用先进技术处理信息以降低或消除虚假警报的发生[ID:7]。\\n\\n以上是T2000火警控制器的主要功能概述。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 13:13:05\",\"id\":34,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一款火警探测和报警系统控制器，集成了多种功能。它能够进行事件记录、设定日期和时间、隔离和解除隔离等操作。T2000控制器的功能分为不同的级别，操作者根据自己的级别登录后才可以操作对应的功能。功能菜单包括但不限于以下内容：确认事件、查看状况、隔离/解除隔离、时间/日期设置、查看和打印事件记录、查看和打印状态、回路点隔离、回路点实测值查看等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。