INSERT INTO `sys_oper_log` VALUES (475, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:39\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。[ID:2] [ID:3] [ID:5]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:39\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac120006\\\",\\\"image_id\\\":\\\"9bd2b88a554d11f099d20242ac120006-d95cbd56c855ed29\\\",\\\"positions\\\":[[1,96,502,105,117],[1,141,547,228,260],[1,113,519,289,324],[2,87,493,103,150],[2,86,4', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:30\",\"id\":44,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:40\",\"id\":45,\"params\":{},\"role\":\"user\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。[ID:2] [ID:3] [ID:5]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:40\",\"id\":46,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac1200', 0, NULL, '2025-07-01 06:02:39', 143);
INSERT INTO `sys_oper_log` VALUES (476, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:08:26\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警探测和报警系统能够执行多项功能，包括但不限于：\\n\\n1. 事件监控：监控火警事件，并在发生火警时提供系统响应。[ID:2]\\n2. 报警器消声：在需要时允许操作者消声报警器。[ID:2]\\n3. 控制器复位：在处理完火警或故障后，可以复位控制器。[ID:2]\\n4. 多个事件处理：能够同时处理多个火警或故障事件。[ID:2]\\n5. 预报警警告：提供预报警功能，以便在火警发生前进行预警。[ID:2]\\n6. 故障处理：在发生系统故障时提供处理步骤和系统反应。[ID:2]\\n7. 时间/日期设置：允许操作者设置和调整系统的时间/日期。[ID:3]\\n8. 事件记录：记录和存储系统事件，便于查看和打印。[ID:3]\\n9. 点的隔离和解除隔离：对特定点进行隔离或解除隔离操作。[ID:3]\\n10. 维护和测试：提供系统维护和测试功能，如测试蜂鸣器、灯和显示器，以及测试蓄电池等。[ID:3] [ID:5]\\n\\n此外，T2000系统还具备不同的登录级别，根据操作者的权限，可以实现更高级别的操作，如修改系统设置、查看状态数据、打印事件记录等。[ID:1] [ID:3]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:08:26\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统能够执行多项功能，包括但不限于：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 事件监控：监控火警事件，并在发生火警时提供系统响应。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 报警器消声：在需要时允许操作者消声报警器。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 控制器复位：在处理完火警或故障后，可以复位控制器。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多个事件处理：能够同时处理多个火警或故障事件。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 预报警警告：提供预报警功能，以便在火警发生前进行预警。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 故障处理：在发生系统故障时提供处理步骤和系统反应。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 时间/日期设置：允许操作者设置和调整系统的时间/日期。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"8. 事件记录：记录和存储系统事件，便于查看和打印。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"9. 点的隔离和解除隔离：对特定点进行隔离或解除隔离操作。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"10. 维护和测试：提供系统维护和测试功能，如测试蜂鸣器、灯和显示器，以及测试蓄电池等。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"此外，T2000系统还具备不同的登录级别，', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:30\",\"id\":44,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:40\",\"id\":45,\"params\":{},\"role\":\"user\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。[ID:2] [ID:3] [ID:5]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:40\",\"id\":46,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac1200', 0, NULL, '2025-07-01 06:08:26', 152);
INSERT INTO `sys_oper_log` VALUES (477, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000有啥优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 16:49:58\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警探测和报警系统具有以下优势：\\n\\n1. 先进技术：使用了泰科MX TechnologyTM技术，这是目前世界上最先进的技术，确保了系统的可靠性和效率。[ID:0]\\n\\n2. 高标准认证：符合欧洲EN54、SOLAS及各大船级社的标准，保证了系统在船运和海洋石油领域的高性能要求。[ID:0]\\n\\n3. 灵活的网络配置：可以通过Peer-to-peer的通讯方式，由最多99个控制器组成一个网络，实现无缝连接和信息共享。[ID:7]\\n\\n4. 多功能：集成电源单元，可为非寻址设备接口模块、非寻址报警器和蜂鸣器、门释放装置和复示器供电。[ID:0]\\n\\n5. 可扩展性：提供2到8个回路，回路可容纳总共1000个点，可分成40/80/120/160/200或240个区，可根据需要扩展系统容量。[ID:0]\\n\\n6. 用户友好：拥有16行x 40字符的大屏幕LCD显示器，可以显示所有域、区和点的详细情况，并提供紧急状态处理程序指导。[ID:7]\\n\\n7. 安全性：通过输入密码登陆进操作者层次，确保了只有授权用户才能进行特定操作。[ID:3]\\n\\n8. 精确的探测：采用特殊技术监控烟雾探头的状态，减少或消除灰尘肮脏对烟雾探头的影响，提高了火灾探测的准确性。[ID:7]\\n\\n9. 自适应环境：可根据外界环境自动或手动改变探头的工作模式和灵敏度，以达到最佳的火灾探测效果。[ID:7]\\n\\n10. 完整的监控和记录：连续监控系统中各个部位的工作情况，并记录最多3000条事件，便于查看、选择和打印。[ID:7]\\n\\n这些优势使T2000成为火警探测和报警系统的优选解决方案。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 16:49:58\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统具有以下优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 先进技术：使用了泰科MX TechnologyTM技术，这是目前世界上最先进的技术，确保了系统的可靠性和效率。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 高标准认证：符合欧洲EN54、SOLAS及各大船级社的标准，保证了系统在船运和海洋石油领域的高性能要求。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 灵活的网络配置：可以通过Peer-to-peer的通讯方式，由最多99个控制器组成一个网络，实现无缝连接和信息共享。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多功能：集成电源单元，可为非寻址设备接口模块、非寻址报警器和蜂鸣器、门释放装置和复示器供电。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 可扩展性：提供2到8个回路，回路可容纳总共1000个点，可分成40/80/120/160/200或240个区，可根据需要扩展系统容量。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 用户友好：拥有16行x 40字符的大屏幕LCD显示器，可以显示所有域、区和点的详细情况，并提供紧急状态处理程序指导。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 安全性：通过输入密码登陆进操作者层次，确保了只有授权用户才能进行特定操作。\\\"},{\\\"type\\\":\\\"btn', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:30\",\"id\":44,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:40\",\"id\":45,\"params\":{},\"role\":\"user\",\"sessionId\":\"f8f1d106564011f0bb000242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。[ID:2] [ID:3] [ID:5]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-01 14:02:40\",\"id\":46,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它集成了先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 该系统具备多种性能和功能，如事件监控、报警器消声、控制器复位等，并提供了不同级别的登录权限，以区分操作者可以执行的功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac1200', 0, NULL, '2025-07-01 08:49:58', 155);
