INSERT INTO `sys_oper_log` VALUES (481, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:25\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"e366f49256e011f09a510242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 系统具备多种功能和性能，例如集成电源单元、不同级别的登陆权限以及多种控制器功能等。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:25\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 系统具备多种功能和性能，例如集成电源单元、不同级别的登陆权限以及多种控制器功能等。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"9bd2b88a554d11f099d20242ac120006\\\",\\\"image_id\\\":\\\"9bd2b88a554d11f099d20242ac120006-d95cbd56c855ed29\\\",\\\"posi', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:15\",\"id\":51,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"e366f49256e011f09a510242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:25\",\"id\":52,\"params\":{},\"role\":\"user\",\"sessionId\":\"e366f49256e011f09a510242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 系统具备多种功能和性能，例如集成电源单元、不同级别的登陆权限以及多种控制器功能等。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:25\",\"id\":53,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 系统具备多种功能和性能，例如集成电源单元、不同级别的登陆权限以及多种控制器功能等。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[