INSERT INTO `sys_oper_log` VALUES (482, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:08:46\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"e366f49256e011f09a510242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警探测和报警系统能够进行以下操作和功能：\\n\\n1. 事件监控和显示：系统可以监控和显示火警事件，包括事件的发生位置和描述。[ID:2]\\n2. 火警响应：在发生火警时，T2000可以发出报警信号，控制蜂鸣器鸣响，点亮火警指示灯，并通过输出端口触发连接的报警器和设备。[ID:6]\\n3. 故障处理：系统能够响应故障，并进行故障处理。[ID:2]\\n4. 多个事件管理：T2000可以处理多个同时发生的火警事件。[ID:2]\\n5. 用户登录级别：系统分为多个用户级别，包括客户操作员、客户经理、工程师和总工程师，每个级别有不同的操作权限。[ID:3]\\n6. 时间和日期设置：可以设置和调整系统的时间、日期，以及夏令时和冬令时的切换。[ID:4]\\n7. 事件记录：系统能够记录最多3000条事件，并可供查看、选择和打印。[ID:7]\\n8. 状态监控：T2000可以连续监控所有探头、手报按钮和输入电路的状况，以获取最准确的系统状态信息，降低虚假警报的概率。[ID:7]\\n9. 探头工作模式和灵敏度调整：根据外部环境，系统可以自动或手动调整探头的工作模式和灵敏度，以达到最佳的火灾探测效果。[ID:7]\\n10. 服务和维护：系统提供了服务和维护菜单，供工程师和总工程师进行系统维护、测试和软件初始化等操作。[ID:3] [ID:4]\\n\\n以上是T2000火警探测和报警系统的主要功能。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:08:46\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警探测和报警系统能够进行以下操作和功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 事件监控和显示：系统可以监控和显示火警事件，包括事件的发生位置和描述。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 火警响应：在发生火警时，T2000可以发出报警信号，控制蜂鸣器鸣响，点亮火警指示灯，并通过输出端口触发连接的报警器和设备。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 故障处理：系统能够响应故障，并进行故障处理。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多个事件管理：T2000可以处理多个同时发生的火警事件。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 用户登录级别：系统分为多个用户级别，包括客户操作员、客户经理、工程师和总工程师，每个级别有不同的操作权限。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 时间和日期设置：可以设置和调整系统的时间、日期，以及夏令时和冬令时的切换。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 事件记录：系统能够记录最多3000条事件，并可供查看、选择和打印。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"8. 状态监控：T2000可以连续监控所有探头、手报按钮和输入电路的状况，以获取最准确的系统状态信息，降低虚假警报的概率。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"9. 探头工作模式和灵敏度调整：根据外部环境，系统', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:15\",\"id\":51,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"e366f49256e011f09a510242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:25\",\"id\":52,\"params\":{},\"role\":\"user\",\"sessionId\":\"e366f49256e011f09a510242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统。[ID:0] 它使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。[ID:1] 系统具备多种功能和性能，例如集成电源单元、不同级别的登陆权限以及多种控制器功能等。[ID:2] [ID:3] [ID:4] [ID:5] [ID:6] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 09:07:25\",\"id\":53,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 它使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\" 系统具备多种功能和性能，例如集成电源单元、不同级别的登陆权限以及多种控制器功能等。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"d95cbd56c855ed29\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac', 0, NULL, '2025-07-02 01:08:45', 221);
