INSERT INTO `sys_oper_log` VALUES (485, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:59\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域[ID:0]。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器[ID:1]。\\n\\nT2000的优势如下：\\n- 采用先进技术，确保系统准确性和降低虚假警报的概率[ID:7]。\\n- 具有可编程的LED显示器和控制键，满足严格标准要求[ID:7]。\\n- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等[ID:7]。\\n- 多层次登录系统，根据不同级别的操作者提供相应的功能权限[ID:2]。\\n- 支持多达99个控制器组成的网络，实现信息共享和无缝连接[ID:7]。\\n- 事件记录功能，可以记录多达3000条事件，方便查看、选择和打印[ID:7]。\\n- 连续监控探头、手报按钮和输入电路的状态，采用先进技术处理信息，降低虚假警报的可能性[ID:7]。\\n\\n综上所述，T2000火警控制器以其高标准的性能和多样化的功能，在火警探测和报警系统中占有优势地位。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:59\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的优势如下：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 采用先进技术，确保系统准确性和降低虚假警报的概率\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具有可编程的LED显示器和控制键，满足严格标准要求\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多层次登录系统，根据不同级别的操作者提供相应的功能权限\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 支持多达99个控制器组成的网络，实现信息共享和无缝连接\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录功能，', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:44\",\"id\":56,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:59\",\"id\":57,\"params\":{},\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域[ID:0]。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器[ID:1]。\\n\\nT2000的优势如下：\\n- 采用先进技术，确保系统准确性和降低虚假警报的概率[ID:7]。\\n- 具有可编程的LED显示器和控制键，满足严格标准要求[ID:7]。\\n- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等[ID:7]。\\n- 多层次登录系统，根据不同级别的操作者提供相应的功能权限[ID:2]。\\n- 支持多达99个控制器组成的网络，实现信息共享和无缝连接[ID:7]。\\n- 事件记录功能，可以记录多达3000条事件，方便查看、选择和打印[ID:7]。\\n- 连续监控探头、手报按钮和输入电路的状态，采用先进技术处理信息，降低虚假警报的可能性[ID:7]。\\n\\n综上所述，T2000火警控制器以其高标准的性能和多样化的功能，在火警探测和报警系统中占有优势地位。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:09:00\",\"id\":58,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的优势如下：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 采用先进技术，确保系统准确性和降低虚假警报的概率\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具有可编程的LED显示器和控制键，满足严格标准要求\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多层次登录系统，根据不同级别的操作者提供相应的功能权限\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}]', 0, NULL, '2025-07-02 05:08:58', 172);
INSERT INTO `sys_oper_log` VALUES (486, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000初学者好上手使用么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:18:47\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警控制器的使用对于初学者来说，可能需要一定的学习和熟悉过程。虽然它具有直观的菜单结构和操作界面，但因其功能复杂且多样，涉及到火警安全的严肃性，所以对初学者来说可能不是非常容易上手[ID:2] [ID:3]。\\n\\n以下是一些考虑因素：\\n\\n1. 多级登录系统：T2000具有多级别的登录权限，不同级别的用户可以操作的功能不同。初学者可能需要时间来理解和适应这些不同的权限和操作级别[ID:2]。\\n\\n2. 功能菜单：T2000的功能菜单较为复杂，包括事件记录、时间/日期设置、回路点隔离等多个选项。初学者需要花费时间学习每个菜单项的功能和操作方法[ID:3]。\\n\\n3. 操作显示模块和控制模块：控制器的前面板上有操作显示模块（ODM800）和操作控制模块（OCM800），初学者需要熟悉这两个模块的功能和操作方法[ID:4]。\\n\\n4. 键盘和软键操作：T2000使用数字键盘和软键进行操作，初学者可能需要练习如何使用这些键进行输入和导航[ID:5]。\\n\\n5. 事件处理：对于火警事件的处理，T2000提供了详细的步骤和显示，但初学者可能在不熟悉的情况下感到困惑，特别是在紧急情况下[ID:6]。\\n\\n6. 维护和诊断：高级功能如维护和诊断可能需要更深入的了解和专业知识，对于初学者来说可能较为困难[ID:5]。\\n\\n总的来说，T2000火警控制器虽然功能强大，但对于初学者来说可能需要通过阅读操作手册、接受培训以及实际操作练习来逐渐熟悉和掌握。因此，它可能不是立即就能轻松上手的设备[ID:0]。 \\n\\n知识库中未找到您要的答案！如果需要更详细的初学者指南或操作建议，建议查阅T2000的官方操作手册或联系技术支持以获得帮助。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:18:47\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警控制器的使用对于初学者来说，可能需要一定的学习和熟悉过程。虽然它具有直观的菜单结构和操作界面，但因其功能复杂且多样，涉及到火警安全的严肃性，所以对初学者来说可能不是非常容易上手\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以下是一些考虑因素：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 多级登录系统：T2000具有多级别的登录权限，不同级别的用户可以操作的功能不同。初学者可能需要时间来理解和适应这些不同的权限和操作级别\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 功能菜单：T2000的功能菜单较为复杂，包括事件记录、时间/日期设置、回路点隔离等多个选项。初学者需要花费时间学习每个菜单项的功能和操作方法\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 操作显示模块和控制模块：控制器的前面板上有操作显示模块（ODM800）和操作控制模块（OCM800），初学者需要熟悉这两个模块的功能和操作方法\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 键盘和软键操作：T2000使用数字键盘和软键进行操作，初学者可能需要练习如何使用这些', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:44\",\"id\":56,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:59\",\"id\":57,\"params\":{},\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域[ID:0]。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器[ID:1]。\\n\\nT2000的优势如下：\\n- 采用先进技术，确保系统准确性和降低虚假警报的概率[ID:7]。\\n- 具有可编程的LED显示器和控制键，满足严格标准要求[ID:7]。\\n- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等[ID:7]。\\n- 多层次登录系统，根据不同级别的操作者提供相应的功能权限[ID:2]。\\n- 支持多达99个控制器组成的网络，实现信息共享和无缝连接[ID:7]。\\n- 事件记录功能，可以记录多达3000条事件，方便查看、选择和打印[ID:7]。\\n- 连续监控探头、手报按钮和输入电路的状态，采用先进技术处理信息，降低虚假警报的可能性[ID:7]。\\n\\n综上所述，T2000火警控制器以其高标准的性能和多样化的功能，在火警探测和报警系统中占有优势地位。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:09:00\",\"id\":58,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的优势如下：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 采用先进技术，确保系统准确性和降低虚假警报的概率\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具有可编程的LED显示器和控制键，满足严格标准要求\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多层次登录系统，根据不同级别的操作者提供相应的功能权限\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}]', 0, NULL, '2025-07-02 05:18:46', 166);
INSERT INTO `sys_oper_log` VALUES (487, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:20:14\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，其主要用途是用于火警探测和报警系统的控制。以下是T2000的一些优势：\\n\\n1. 先进技术：T2000使用了泰科公司的MX TechnologyTM技术，这是一种先进的技术，确保了系统的可靠性和效率。[ID:0]\\n\\n2. 广泛应用：T2000满足欧洲EN54、SOLAS以及全球各大船级社的标准，适用于船运和海洋石油领域，具有广泛的应用范围。[ID:0]\\n\\n3. 多样化的功能：T2000具有集成电源单元、回路点容纳能力、区域划分、网络组建等功能，并且具有船用证书，适用于各种环境。[ID:1]\\n\\n4. 多级用户权限：T2000设置了不同的用户级别，包括客户操作员、经理、工程师和总工程师，确保了操作的安全性和功能性。[ID:2]\\n\\n5. 直观的界面：T2000配备了16行x 40字符的大屏幕LCD显示器，可以直观地显示系统状态、火警数、故障数等信息。[ID:7]\\n\\n6. 网络能力：T2000支持多达99个控制器组成的网络，实现信息共享和无缝连接，增强了系统的扩展性。[ID:7]\\n\\n7. 事件记录：T2000能够记录多达3000条事件，方便用户查看、选择和打印，有助于事件分析和系统维护。[ID:7]\\n\\n8. 准确性：T2000采用特殊技术监控探头状态，减少虚假警报的可能性，提高了火警探测的准确性。[ID:7]\\n\\n9. 灵活性和适应性：T2000可以根据外部环境自动或手动调整探头工作模式和灵敏度，以达到最佳的火灾探测效果。[ID:7]\\n\\n综上所述，T2000火警控制器以其强大的功能、高标准的性能和适应性强等特点，在火警探测和报警系统中具有显著的优势。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:20:14\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，其主要用途是用于火警探测和报警系统的控制。以下是T2000的一些优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 先进技术：T2000使用了泰科公司的MX TechnologyTM技术，这是一种先进的技术，确保了系统的可靠性和效率。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 广泛应用：T2000满足欧洲EN54、SOLAS以及全球各大船级社的标准，适用于船运和海洋石油领域，具有广泛的应用范围。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 多样化的功能：T2000具有集成电源单元、回路点容纳能力、区域划分、网络组建等功能，并且具有船用证书，适用于各种环境。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多级用户权限：T2000设置了不同的用户级别，包括客户操作员、经理、工程师和总工程师，确保了操作的安全性和功能性。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 直观的界面：T2000配备了16行x 40字符的大屏幕LCD显示器，可以直观地显示系统状态、火警数、故障数等信息。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 网络能力：T2000支持多达99个控制器组成的网络，实现信息共享和无缝连接，增强了系统的扩展性。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 事件记录：T200', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:44\",\"id\":56,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:59\",\"id\":57,\"params\":{},\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域[ID:0]。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器[ID:1]。\\n\\nT2000的优势如下：\\n- 采用先进技术，确保系统准确性和降低虚假警报的概率[ID:7]。\\n- 具有可编程的LED显示器和控制键，满足严格标准要求[ID:7]。\\n- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等[ID:7]。\\n- 多层次登录系统，根据不同级别的操作者提供相应的功能权限[ID:2]。\\n- 支持多达99个控制器组成的网络，实现信息共享和无缝连接[ID:7]。\\n- 事件记录功能，可以记录多达3000条事件，方便查看、选择和打印[ID:7]。\\n- 连续监控探头、手报按钮和输入电路的状态，采用先进技术处理信息，降低虚假警报的可能性[ID:7]。\\n\\n综上所述，T2000火警控制器以其高标准的性能和多样化的功能，在火警探测和报警系统中占有优势地位。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:09:00\",\"id\":58,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，它使用了泰科公司先进的MX TechnologyTM技术，满足欧洲EN54、SOLAS以及全球各大船级社的标准，广泛应用于船运和海洋石油领域\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。T2000的主要性能和功能包括集成电源单元、可容纳多达1000个点的回路、可分成不同区域、可组网、拥有船用证书，以及全功能的火警复示器\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的优势如下：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 采用先进技术，确保系统准确性和降低虚假警报的概率\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具有可编程的LED显示器和控制键，满足严格标准要求\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 16行x 40字符的大屏幕LCD显示器，可以显示系统状态的详细信息，包括火警数、故障数等\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多层次登录系统，根据不同级别的操作者提供相应的功能权限\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}]', 0, NULL, '2025-07-02 05:20:13', 229);
