INSERT INTO `sys_oper_log` VALUES (491, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:28:11\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种专业的火警控制器，主要用于火警探测和报警系统。以下是T2000的主要用途和优势：\\n\\n用途：\\n- T2000火警控制器适用于船舶、海洋石油平台等环境，提供火灾探测和报警功能，确保人员安全和财产安全。\\n\\n优势：\\n1. 先进技术：采用泰科公司的MX TechnologyTM技术，符合欧洲EN54、SOLAS等国际标准，保证了系统的先进性和可靠性。[ID:0]\\n2. 灵活配置：支持2到8个回路，可容纳1000个点，可以根据需要分成不同数量的区域，适应不同的安装需求。[ID:0]\\n3. 网络化：支持组网，最多可以由99个控制器组成网络，实现信息共享和集中管理。[ID:7]\\n4. 用户界面：配备16行x 40字符的LCD显示器，提供清晰的系统状态显示和操作指南，便于用户快速了解和处理火警事件。[ID:7]\\n5. 多级权限：设有多个用户级别，包括客户操作员、经理、工程师等，确保只有授权人员才能进行关键操作。[ID:2]\\n6. 事件记录：能够记录最多3000条事件，便于事后分析、故障诊断和合规性记录。[ID:7]\\n7. 准确性：采用特殊技术减少虚假警报，提高火灾探测的准确性。[ID:7]\\n8. 可维护性：提供详细的维护和诊断功能，帮助用户进行日常检查和故障排除。[ID:4]\\n\\nT2000火警控制器的这些优势使其在火警探测和报警系统中具有较高的性能和可靠性，适用于要求严格的安全环境。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:28:11\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种专业的火警控制器，主要用于火警探测和报警系统。以下是T2000的主要用途和优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"用途：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- T2000火警控制器适用于船舶、海洋石油平台等环境，提供火灾探测和报警功能，确保人员安全和财产安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 先进技术：采用泰科公司的MX TechnologyTM技术，符合欧洲EN54、SOLAS等国际标准，保证了系统的先进性和可靠性。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 灵活配置：支持2到8个回路，可容纳1000个点，可以根据需要分成不同数量的区域，适应不同的安装需求。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 网络化：支持组网，最多可以由99个控制器组成网络，实现信息共享和集中管理。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 用户界面：配备16行x 40字符的LCD显示器，提供清晰的系统状态显示和操作指南，便于用户快速了解和处理火警事件。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 多级权限：设有多个用户级别，包括客户操作员、经理、工程师等，确保只有授权人员才能进行关键操作。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 事件记录：能够记录最多3000条事件，便于事后分析、故障诊断和合规性记录。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"valu', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:44\",\"id\":56,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是做什么的有什么优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:28:12\",\"id\":63,\"params\":{},\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种专业的火警控制器，主要用于火警探测和报警系统。以下是T2000的主要用途和优势：\\n\\n用途：\\n- T2000火警控制器适用于船舶、海洋石油平台等环境，提供火灾探测和报警功能，确保人员安全和财产安全。\\n\\n优势：\\n1. 先进技术：采用泰科公司的MX TechnologyTM技术，符合欧洲EN54、SOLAS等国际标准，保证了系统的先进性和可靠性。[ID:0]\\n2. 灵活配置：支持2到8个回路，可容纳1000个点，可以根据需要分成不同数量的区域，适应不同的安装需求。[ID:0]\\n3. 网络化：支持组网，最多可以由99个控制器组成网络，实现信息共享和集中管理。[ID:7]\\n4. 用户界面：配备16行x 40字符的LCD显示器，提供清晰的系统状态显示和操作指南，便于用户快速了解和处理火警事件。[ID:7]\\n5. 多级权限：设有多个用户级别，包括客户操作员、经理、工程师等，确保只有授权人员才能进行关键操作。[ID:2]\\n6. 事件记录：能够记录最多3000条事件，便于事后分析、故障诊断和合规性记录。[ID:7]\\n7. 准确性：采用特殊技术减少虚假警报，提高火灾探测的准确性。[ID:7]\\n8. 可维护性：提供详细的维护和诊断功能，帮助用户进行日常检查和故障排除。[ID:4]\\n\\nT2000火警控制器的这些优势使其在火警探测和报警系统中具有较高的性能和可靠性，适用于要求严格的安全环境。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:28:12\",\"id\":64,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种专业的火警控制器，主要用于火警探测和报警系统。以下是T2000的主要用途和优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"用途：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- T2000火警控制器适用于船舶、海洋石油平台等环境，提供火灾探测和报警功能，确保人员安全和财产安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 先进技术：采用泰科公司的MX TechnologyTM技术，符合欧洲EN54、SOLAS等国际标准，保证了系统的先进性和可靠性。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 灵活配置：支持2到8个回路，可容纳1000个点，可以根据需要分成不同数量的区域，适应不同的安装需求。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 网络化：支持组网，最多可以由99个控制器组成网络，实现信息共享和集中管理。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 用户界面：配备16行x 40字符的LCD显示器，提供清晰的系统状态显示和操作指南，便于用户快速了解和处理火警事件。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 多级权限：设有多个用户级别，包括客户操作员、经理、工程师等，确保只有授权人员才能进行关', 0, NULL, '2025-07-02 06:28:11', 151);
INSERT INTO `sys_oper_log` VALUES (492, '聊天记录同步', 3, 'com.gaisoft.kb.controller.KbChatController.remove()', 'DELETE', 1, 'admin', '研发部门11', '/aftersales/chat/63,64', '192.168.1.101', '内网IP', '[63,64]', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-07-02 06:29:22', 54);
INSERT INTO `sys_oper_log` VALUES (493, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是干啥的\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:29:53\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，主要用于火警探测和报警系统。它的主要功能包括：\\n\\n1. 火灾探测：T2000能够监测和控制火警探测设备，如烟雾探测器、温度探测器等，以发现潜在的火灾危险。\\n\\n2. 报警通知：一旦检测到火灾迹象，T2000会立即触发报警，通过声音、灯光和其他方式通知船上或海洋石油平台上的人员。\\n\\n3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等管理功能，帮助用户维护和管理火警系统。\\n\\n4. 用户界面：配备了LCD显示器和操作控制模块，T2000的用户界面直观，便于操作者监控系统状态和处理火警事件。\\n\\n5. 网络集成：T2000支持网络集成，可以与其他控制器联网，实现信息共享和集中控制。\\n\\nT2000的主要优势包括：\\n- 采用先进技术，满足高标准的国际安全规范。\\n- 具有灵活的配置，适应不同规模和需求的火警探测系统。\\n- 提供多级用户权限，确保只有授权人员可以执行关键操作。\\n- 具备事件记录功能，方便追踪和分析火警事件。\\n- 支持网络化部署，便于大规模系统的集中管理和监控。\\n\\n简而言之，T2000是用于提高火灾安全性、保护人员和财产的关键设备，特别是在船舶和海洋石油领域。[ID:0] [ID:1] [ID:2] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:29:53\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，主要用于火警探测和报警系统。它的主要功能包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 火灾探测：T2000能够监测和控制火警探测设备，如烟雾探测器、温度探测器等，以发现潜在的火灾危险。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 报警通知：一旦检测到火灾迹象，T2000会立即触发报警，通过声音、灯光和其他方式通知船上或海洋石油平台上的人员。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等管理功能，帮助用户维护和管理火警系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 用户界面：配备了LCD显示器和操作控制模块，T2000的用户界面直观，便于操作者监控系统状态和处理火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 网络集成：T2000支持网络集成，可以与其他控制器联网，实现信息共享和集中控制。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的主要优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 采用先进技术，满足高标准的国际安全规范。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具有灵活的配置，适应不同规模和需求的火警探测系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 提供多级用户权限，确保只有授权人员可以执行关键操作。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具备事件记录功能，方便追踪和分析火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 支持网络化部署，便于大规模系统的集中管理和监控。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"简而言之，T2000是用于提高火灾安全性、保护人员和财产的关键设备，特别是在船舶和海洋石油领域。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"va', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:44\",\"id\":56,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是干啥的\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:29:53\",\"id\":65,\"params\":{},\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，主要用于火警探测和报警系统。它的主要功能包括：\\n\\n1. 火灾探测：T2000能够监测和控制火警探测设备，如烟雾探测器、温度探测器等，以发现潜在的火灾危险。\\n\\n2. 报警通知：一旦检测到火灾迹象，T2000会立即触发报警，通过声音、灯光和其他方式通知船上或海洋石油平台上的人员。\\n\\n3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等管理功能，帮助用户维护和管理火警系统。\\n\\n4. 用户界面：配备了LCD显示器和操作控制模块，T2000的用户界面直观，便于操作者监控系统状态和处理火警事件。\\n\\n5. 网络集成：T2000支持网络集成，可以与其他控制器联网，实现信息共享和集中控制。\\n\\nT2000的主要优势包括：\\n- 采用先进技术，满足高标准的国际安全规范。\\n- 具有灵活的配置，适应不同规模和需求的火警探测系统。\\n- 提供多级用户权限，确保只有授权人员可以执行关键操作。\\n- 具备事件记录功能，方便追踪和分析火警事件。\\n- 支持网络化部署，便于大规模系统的集中管理和监控。\\n\\n简而言之，T2000是用于提高火灾安全性、保护人员和财产的关键设备，特别是在船舶和海洋石油领域。[ID:0] [ID:1] [ID:2] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:29:54\",\"id\":66,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，主要用于火警探测和报警系统。它的主要功能包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 火灾探测：T2000能够监测和控制火警探测设备，如烟雾探测器、温度探测器等，以发现潜在的火灾危险。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 报警通知：一旦检测到火灾迹象，T2000会立即触发报警，通过声音、灯光和其他方式通知船上或海洋石油平台上的人员。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等管理功能，帮助用户维护和管理火警系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 用户界面：配备了LCD显示器和操作控制模块，T2000的用户界面直观，便于操作者监控系统状态和处理火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 网络集成：T2000支持网络集成，可以与其他控制器联网，实现信息共享和集中控制。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的主要优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 采用先进技术，满足高标准的国际安全规范。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具有灵活的配置，适应不同规模和需求的火警探测系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 提供多级用户权限，确保只有授权人员可以执行关键操作。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 具备事件记录功能，方便追踪和分析火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 支持网络化部署，便于大规模系统的集中管理和监控。', 0, NULL, '2025-07-02 06:29:53', 149);
