INSERT INTO `sys_oper_log` VALUES (495, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是干啥的\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:31:01\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统的控制器。它的主要作用是监测火警探测设备的状态，一旦检测到火灾迹象，就会立即启动报警程序，通知相关人员采取行动。以下是T2000的主要功能：\\n\\n1. 火灾监测：T2000能够监控和控制多种类型的火警探测设备，如烟雾探测器、热探测器、火焰探测器等。\\n\\n2. 报警控制：在检测到火警时，T2000会激活报警系统，包括声音报警、灯光闪烁等，以确保及时通知船上或海洋石油平台上的所有人员。\\n\\n3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等功能，帮助用户管理和维护火警系统。\\n\\n4. 用户界面：T2000配备了易于操作的LCD显示屏和键盘，使得操作者可以轻松监控系统状态和处理火警事件。\\n\\n5. 多级权限：T2000设有多个用户级别，包括客户操作员、经理、工程师等，以确保只有授权人员可以访问和操作关键功能。\\n\\n6. 网络集成：T2000支持网络连接，可以与其他控制器联网，实现数据共享和集中管理。\\n\\nT2000的主要优势包括：\\n- 先进的技术，符合国际安全标准。\\n- 灵活的配置，适应不同环境和规模的火警探测系统。\\n- 多级用户权限，保障系统安全。\\n- 事件记录功能，便于分析和追踪火警事件。\\n- 网络化设计，便于大规模部署和管理。\\n\\n总的来说，T2000是确保火灾安全、保护人员和财产的重要设备，尤其是在船舶和海洋石油领域。[ID:0] [ID:1] [ID:2] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:31:01\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统的控制器。它的主要作用是监测火警探测设备的状态，一旦检测到火灾迹象，就会立即启动报警程序，通知相关人员采取行动。以下是T2000的主要功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 火灾监测：T2000能够监控和控制多种类型的火警探测设备，如烟雾探测器、热探测器、火焰探测器等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 报警控制：在检测到火警时，T2000会激活报警系统，包括声音报警、灯光闪烁等，以确保及时通知船上或海洋石油平台上的所有人员。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等功能，帮助用户管理和维护火警系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 用户界面：T2000配备了易于操作的LCD显示屏和键盘，使得操作者可以轻松监控系统状态和处理火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 多级权限：T2000设有多个用户级别，包括客户操作员、经理、工程师等，以确保只有授权人员可以访问和操作关键功能。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 网络集成：T2000支持网络连接，可以与其他控制器联网，实现数据共享和集中管理。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的主要优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 先进的技术，符合国际安全标准。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 灵活的配置，适应不同环境和规模的火警探测系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 多级用户权限，保障系统安全。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 事件记录功能，便于分析和追踪火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"va', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 13:08:44\",\"id\":56,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是干啥的\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:31:02\",\"id\":67,\"params\":{},\"role\":\"user\",\"sessionId\":\"9f9a426a570211f09d430242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警探测和报警系统的控制器。它的主要作用是监测火警探测设备的状态，一旦检测到火灾迹象，就会立即启动报警程序，通知相关人员采取行动。以下是T2000的主要功能：\\n\\n1. 火灾监测：T2000能够监控和控制多种类型的火警探测设备，如烟雾探测器、热探测器、火焰探测器等。\\n\\n2. 报警控制：在检测到火警时，T2000会激活报警系统，包括声音报警、灯光闪烁等，以确保及时通知船上或海洋石油平台上的所有人员。\\n\\n3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等功能，帮助用户管理和维护火警系统。\\n\\n4. 用户界面：T2000配备了易于操作的LCD显示屏和键盘，使得操作者可以轻松监控系统状态和处理火警事件。\\n\\n5. 多级权限：T2000设有多个用户级别，包括客户操作员、经理、工程师等，以确保只有授权人员可以访问和操作关键功能。\\n\\n6. 网络集成：T2000支持网络连接，可以与其他控制器联网，实现数据共享和集中管理。\\n\\nT2000的主要优势包括：\\n- 先进的技术，符合国际安全标准。\\n- 灵活的配置，适应不同环境和规模的火警探测系统。\\n- 多级用户权限，保障系统安全。\\n- 事件记录功能，便于分析和追踪火警事件。\\n- 网络化设计，便于大规模部署和管理。\\n\\n总的来说，T2000是确保火灾安全、保护人员和财产的重要设备，尤其是在船舶和海洋石油领域。[ID:0] [ID:1] [ID:2] [ID:7]\",\"createBy\":\"admin\",\"createTime\":\"2025-07-02 14:31:02\",\"id\":68,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警探测和报警系统的控制器。它的主要作用是监测火警探测设备的状态，一旦检测到火灾迹象，就会立即启动报警程序，通知相关人员采取行动。以下是T2000的主要功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 火灾监测：T2000能够监控和控制多种类型的火警探测设备，如烟雾探测器、热探测器、火焰探测器等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 报警控制：在检测到火警时，T2000会激活报警系统，包括声音报警、灯光闪烁等，以确保及时通知船上或海洋石油平台上的所有人员。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 系统管理：T2000提供了系统状态监控、事件记录、时间/日期设置、回路点隔离等功能，帮助用户管理和维护火警系统。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 用户界面：T2000配备了易于操作的LCD显示屏和键盘，使得操作者可以轻松监控系统状态和处理火警事件。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 多级权限：T2000设有多个用户级别，包括客户操作员、经理、工程师等，以确保只有授权人员可以访问和操作关键功能。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 网络集成：T2000支持网络连接，可以与其他控制器联网，实现数据共享和集中管理。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000的主要优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 先进的技术，符合国际安全标准。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"', 0, NULL, '2025-07-02 06:31:01', 152);
