INSERT INTO `sys_oper_log` VALUES (499, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是啥呢么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 09:59:46\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"52f7f57457b111f0b6be0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，它使用了目前世界上最先进的泰科MX TechnologyTM技术[ID:0]。该控制器满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用[ID:0]。T2000火警控制器具有多种功能，如事件监控、设定日期和时间、火警报警等，并且可以根据不同用户的级别限制对功能的访问[ID:2] [ID:3]。它还包括集成电源单元，可为非寻址设备接口模块、报警器、门释放装置和复示器等供电[ID:0]。此外，T2000还支持多种辅助显示设备，如复示器和打印机[ID:5]。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 09:59:46\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，它使用了目前世界上最先进的泰科MX TechnologyTM技术\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。该控制器满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。T2000火警控制器具有多种功能，如事件监控、设定日期和时间、火警报警等，并且可以根据不同用户的级别限制对功能的访问\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它还包括集成电源单元，可为非寻址设备接口模块、报警器、门释放装置和复示器等供电\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。此外，T2000还支持多种辅助显示设备，如复示器和打印机\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"0a15c9934098ffbf\\\",\\\"content\\\":\\\"T2000火警控制器使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。泰科标准的MINERVA MX火警控制器包括：•MX1000 火警控制器–1个回路、回路可容纳250个点、可分成40/80/120/160/200或240个区、可组网；•MX4000火警控制器–2到4回路、回路可容纳总共1000个点、可分成40/80/120/160/200或240个区、可组•网（紧凑型）；.MX4000M火警控制器–2到4回路、回路可容纳总共1000个点、可分成40/80/120/160/200或240个区、可组•网；T2000火警控制器–2到8回路、回路可容纳总共1000个点、可分成40/80/120/160/200或240个区、可组网、有船用证书；.•MXR 火警复示器–全功能火警复示器；•T2000R火警复示器－船用全功能复示器；1.2 T2000系统的主要性能和功能•集成电源单元：输入交流110-250V、后备电源24V蓄电池、输出电流可达5A (报警时的负载)，该电源可为非寻址设备接口模块(DIM800)、非寻址报警器和蜂鸣器、门释放装置和复示器供电；•电源单元集成有直流24V充电器，可以为最大38Ah的蓄电池充电；\\\",\\\"document_id\\\":\\\"da1acb00554d11f08cff0242ac120006\\\",\\\"documen', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 09:59:18\",\"id\":69,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"52f7f57457b111f0b6be0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是啥呢么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 09:59:46\",\"id\":72,\"params\":{},\"role\":\"user\",\"sessionId\":\"52f7f57457b111f0b6be0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种火警控制器，它使用了目前世界上最先进的泰科MX TechnologyTM技术[ID:0]。该控制器满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用[ID:0]。T2000火警控制器具有多种功能，如事件监控、设定日期和时间、火警报警等，并且可以根据不同用户的级别限制对功能的访问[ID:2] [ID:3]。它还包括集成电源单元，可为非寻址设备接口模块、报警器、门释放装置和复示器等供电[ID:0]。此外，T2000还支持多种辅助显示设备，如复示器和打印机[ID:5]。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 09:59:46\",\"id\":73,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种火警控制器，它使用了目前世界上最先进的泰科MX TechnologyTM技术\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。该控制器满足欧洲EN54、SOLAS及世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。T2000火警控制器具有多种功能，如事件监控、设定日期和时间、火警报警等，并且可以根据不同用户的级别限制对功能的访问\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它还包括集成电源单元，可为非寻址设备接口模块、报警器、门释放装置和复示器等供电\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。此外，T2000还支持多种辅助显示设备，如复示器和打印机\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"0a15c9934098ffbf\\\",\\\"content\\\":\\\"T2000火警控制器使用了目前世界上最先进的泰科MX TechnologyTM技术，满足欧洲EN54、SOLAS及各世界上各大船级社的标准，在船运和海洋石油领域得到了广泛的应用。泰科标准的MINERVA MX火警控制器包括：•MX1000 火警控制器–1个回路、回路可容纳250个点、可分成40/80/120/160/200或240个区、可组网；•MX4000火警控制器–2到4回路、回路可容纳总共1000个点、可分成40/80/120/160/200或240个区、可组•网（紧凑型）；.MX4000M火警控制器–2到4回路、回路可容纳总共1000个点、可分成40/80/120/160/200或240个区、可组•网；T2000火警控制器–2到8回路、回路可容纳总共1000个点、可分成40/80/120/160/200或240个区、可组网、有船用证书；.•MXR 火警复示器–全功能火警复示器；•T2000R火警复示器－船用全功能复示器；1.2 T2000系统的主要性能和功能•集成电源单元：输入交流110-250V、后', 0, NULL, '2025-07-03 01:59:45', 135);
