INSERT INTO `sys_oper_log` VALUES (509, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能干什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:08:21\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"82e9246057b111f083cc0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警控制器是一个集成了多种功能的系统，它能够进行以下操作和功能：\\n\\n1. 事件监控：T2000可以监控火警事件，并在发生火警时提供系统响应。[ID:1]\\n   \\n2. 显示和操作：它具备液晶显示器，可以显示火警窗口、状态窗口、主窗口和软键窗口，供操作者进行事件显示和系统操作。[ID:2]\\n\\n3. 多级用户登录：T2000将操作功能分为不同的级别，包括客户操作员、客户经理、工程师和总工程师，根据用户级别登录后，操作者可以执行相应级别的功能。[ID:0]\\n\\n4. 时间和日期设置：控制器允许设定日期和时间，包括夏令时和冬令时的调整。[ID:4]\\n\\n5. 事件记录：可以记录和查看事件日志，并支持打印事件记录。[ID:0] [ID:4]\\n\\n6. 状态查看和打印：T2000提供了查看和打印系统状态数据的功能，如点的隔离情况、未测试/故障情况以及实测值等。[ID:4]\\n\\n7. 故障处理：在发生故障时，系统会有反应，并提供故障处理流程。[ID:1]\\n\\n8. 服务和维护：提供了如人为测试状态、火警循环计数、维护请求、测试蓄电池等服务和维护功能。[ID:3] [ID:4]\\n\\n9. 组网：T2000支持与其他控制器组成网络，实现信息共享。[ID:2]\\n\\n10. 探头和工作状态监控：系统持续监控探头、手报按钮和输入电路的状况，并处理信息以获得准确的系统状态，降低虚假警报的概率。[ID:7]\\n\\n以上是T2000火警控制器的主要功能。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:08:21\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警控制器是一个集成了多种功能的系统，它能够进行以下操作和功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 事件监控：T2000可以监控火警事件，并在发生火警时提供系统响应。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1}],[],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 显示和操作：它具备液晶显示器，可以显示火警窗口、状态窗口、主窗口和软键窗口，供操作者进行事件显示和系统操作。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 多级用户登录：T2000将操作功能分为不同的级别，包括客户操作员、客户经理、工程师和总工程师，根据用户级别登录后，操作者可以执行相应级别的功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 时间和日期设置：控制器允许设定日期和时间，包括夏令时和冬令时的调整。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 事件记录：可以记录和查看事件日志，并支持打印事件记录。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 状态查看和打印：T2000提供了查看和打印系统状态数据的功能，如点的隔离情况、未测试/故障情况以及实测值等。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 故障处理：在发生故障时，系统会有反应，并提供故障处理流程。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"8. 服务和维护：提供了如人为测试状态、火警循环计数、维护请求、测试蓄电池', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:00:38\",\"id\":77,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"82e9246057b111f083cc0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能干什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:08:21\",\"id\":80,\"params\":{},\"role\":\"user\",\"sessionId\":\"82e9246057b111f083cc0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000火警控制器是一个集成了多种功能的系统，它能够进行以下操作和功能：\\n\\n1. 事件监控：T2000可以监控火警事件，并在发生火警时提供系统响应。[ID:1]\\n   \\n2. 显示和操作：它具备液晶显示器，可以显示火警窗口、状态窗口、主窗口和软键窗口，供操作者进行事件显示和系统操作。[ID:2]\\n\\n3. 多级用户登录：T2000将操作功能分为不同的级别，包括客户操作员、客户经理、工程师和总工程师，根据用户级别登录后，操作者可以执行相应级别的功能。[ID:0]\\n\\n4. 时间和日期设置：控制器允许设定日期和时间，包括夏令时和冬令时的调整。[ID:4]\\n\\n5. 事件记录：可以记录和查看事件日志，并支持打印事件记录。[ID:0] [ID:4]\\n\\n6. 状态查看和打印：T2000提供了查看和打印系统状态数据的功能，如点的隔离情况、未测试/故障情况以及实测值等。[ID:4]\\n\\n7. 故障处理：在发生故障时，系统会有反应，并提供故障处理流程。[ID:1]\\n\\n8. 服务和维护：提供了如人为测试状态、火警循环计数、维护请求、测试蓄电池等服务和维护功能。[ID:3] [ID:4]\\n\\n9. 组网：T2000支持与其他控制器组成网络，实现信息共享。[ID:2]\\n\\n10. 探头和工作状态监控：系统持续监控探头、手报按钮和输入电路的状况，并处理信息以获得准确的系统状态，降低虚假警报的概率。[ID:7]\\n\\n以上是T2000火警控制器的主要功能。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:08:21\",\"id\":81,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000火警控制器是一个集成了多种功能的系统，它能够进行以下操作和功能：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 事件监控：T2000可以监控火警事件，并在发生火警时提供系统响应。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1}],[],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 显示和操作：它具备液晶显示器，可以显示火警窗口、状态窗口、主窗口和软键窗口，供操作者进行事件显示和系统操作。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 多级用户登录：T2000将操作功能分为不同的级别，包括客户操作员、客户经理、工程师和总工程师，根据用户级别登录后，操作者可以执行相应级别的功能。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 时间和日期设置：控制器允许设定日期和时间，包括夏令时和冬令时的调整。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 事件记录：可以记录和查看事件日志，并支持打印事件记录。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 状态查看和打印：T2000提供了查看和打印系统状态数据的功能，如点的隔离情况、未测试/故障情况以及实测值等。\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\"', 0, NULL, '2025-07-03 02:08:19', 154);
