INSERT INTO `sys_oper_log` VALUES (511, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/session', '192.168.1.101', '内网IP', '{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:12:54\",\"id\":47,\"params\":{},\"sessionId\":\"39de672e57b311f0baec0242ac120006\",\"sessionName\":\"T2000能做啥\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:12:54\",\"id\":47,\"params\":{},\"sessionId\":\"39de672e57b311f0baec0242ac120006\",\"sessionName\":\"T2000能做啥\"}}', 0, NULL, '2025-07-03 02:12:53', 206);
INSERT INTO `sys_oper_log` VALUES (512, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:13:28\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"39de672e57b311f0baec0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统，具有以下主要性能和功能[ID:2]：\\n\\n1. **火警探测和报警**：T2000可以监测火警事件，并在发生火警时发出警报，通过内置蜂鸣器和连接的报警器进行声音报警，同时在液晶显示器上显示相关信息[ID:6]。\\n\\n2. **事件监控与显示**：系统可以监控事件，显示事件详情，如事件发生的位置和类型，并允许操作者查看事件记录[ID:0]。\\n\\n3. **操作显示与控制**：T2000拥有面板显示和控制模块，包括火警窗口、状态窗口、主窗口和软键窗口等，用于系统的日常操作[ID:1]。\\n\\n4. **多级别用户管理**：系统支持不同级别的用户登录，包括客户操作员、客户经理、工程师和总工程师等，每个级别的用户有不同的操作权限[ID:3]。\\n\\n5. **时间/日期设置**：可以设置和调整系统的时间与日期，包括夏令时和冬令时的切换[.ID:4]。\\n\\n6. **事件记录与打印**：T2000能记录事件，并提供打印事件记录的功能[ID:4]。\\n\\n7. **系统维护与服务**：提供系统维护功能，如人为测试状态、维护请求、测试蓄电池等，以及软件版本和项目号等信息的查看[IDs:3]。\\n\\n8. **组态与配置**：工程师和总工程师级别的用户可以更改系统配置，包括更改描述文字、测试蜂鸣器和灯等[IDs:3]。\\n\\n9. **回路点隔离与查看**：系统允许用户隔离或解除隔离回路点，并可以查看回路点的实测值和状态[IDs:4]。\\n\\n10. **扩展功能**：T2000支持组网，可以与其他火警控制器和复示器连接，适用于大型和复杂的火警报警系统[ID:2]。\\n\\n11. **满足国际标准**：T2000满足欧洲EN54、SOLAS等国际标准，适用于船运和海洋石油领域[ID:2]。\\n\\n以上是T2000火警探测和报警系统的主要功能。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:13:28\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统，具有以下主要性能和功能\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警探测和报警**：T2000可以监测火警事件，并在发生火警时发出警报，通过内置蜂鸣器和连接的报警器进行声音报警，同时在液晶显示器上显示相关信息\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件监控与显示**：系统可以监控事件，显示事件详情，如事件发生的位置和类型，并允许操作者查看事件记录\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **操作显示与控制**：T2000拥有面板显示和控制模块，包括火警窗口、状态窗口、主窗口和软键窗口等，用于系统的日常操作\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **多级别用户管理**：系统支持不同级别的用户登录，包括客户操作员、客户经理、工程师和总工程师等，每个级别的用户有不同的操作权限\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:12:54\",\"id\":82,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"39de672e57b311f0baec0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:13:28\",\"id\":83,\"params\":{},\"role\":\"user\",\"sessionId\":\"39de672e57b311f0baec0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统，具有以下主要性能和功能[ID:2]：\\n\\n1. **火警探测和报警**：T2000可以监测火警事件，并在发生火警时发出警报，通过内置蜂鸣器和连接的报警器进行声音报警，同时在液晶显示器上显示相关信息[ID:6]。\\n\\n2. **事件监控与显示**：系统可以监控事件，显示事件详情，如事件发生的位置和类型，并允许操作者查看事件记录[ID:0]。\\n\\n3. **操作显示与控制**：T2000拥有面板显示和控制模块，包括火警窗口、状态窗口、主窗口和软键窗口等，用于系统的日常操作[ID:1]。\\n\\n4. **多级别用户管理**：系统支持不同级别的用户登录，包括客户操作员、客户经理、工程师和总工程师等，每个级别的用户有不同的操作权限[ID:3]。\\n\\n5. **时间/日期设置**：可以设置和调整系统的时间与日期，包括夏令时和冬令时的切换[.ID:4]。\\n\\n6. **事件记录与打印**：T2000能记录事件，并提供打印事件记录的功能[ID:4]。\\n\\n7. **系统维护与服务**：提供系统维护功能，如人为测试状态、维护请求、测试蓄电池等，以及软件版本和项目号等信息的查看[IDs:3]。\\n\\n8. **组态与配置**：工程师和总工程师级别的用户可以更改系统配置，包括更改描述文字、测试蜂鸣器和灯等[IDs:3]。\\n\\n9. **回路点隔离与查看**：系统允许用户隔离或解除隔离回路点，并可以查看回路点的实测值和状态[IDs:4]。\\n\\n10. **扩展功能**：T2000支持组网，可以与其他火警控制器和复示器连接，适用于大型和复杂的火警报警系统[ID:2]。\\n\\n11. **满足国际标准**：T2000满足欧洲EN54、SOLAS等国际标准，适用于船运和海洋石油领域[ID:2]。\\n\\n以上是T2000火警探测和报警系统的主要功能。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:13:28\",\"id\":84,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统，具有以下主要性能和功能\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警探测和报警**：T2000可以监测火警事件，并在发生火警时发出警报，通过内置蜂鸣器和连接的报警器进行声音报警，同时在液晶显示器上显示相关信息\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":6},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件监控与显示**：系统可以监控事件，显示事件详情，如事件发生的位置和类型，并允许操作者查看事件记录\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **操作显示与控制**：T2000拥有面板显示和控制模块，包括火警窗口、状态窗口、主窗口和软键窗口等，用于系统的日常操作\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"', 0, NULL, '2025-07-03 02:13:26', 122);
