INSERT INTO `sys_oper_log` VALUES (514, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 14:15:38\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"39de672e57b311f0baec0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统，它集成了多种功能，包括但不限于以下几项：[ID:0] [ID:1] [ID:2]\\n\\n1. 事件监控：T2000能够监控火警事件，并在发生火警时提供及时的报警响应。\\n2. 显示功能：系统配备了液晶显示器，可以显示火警窗口、状态窗口、主窗口以及软键窗口等，用于显示各种系统状态和警告信息。\\n3. 控制器操作：T2000允许操作者通过控制器进行事件监控、事件显示以及系统设置等操作。\\n4. 多级用户权限：系统将操作功能分成了不同的级别，包括客户操作员、客户经理、工程师以及总工程师等，不同级别的用户登录后可以操作对应的功能。\\n5. 时间/日期设置：操作者可以设置和调整系统的时间/日期，包括夏令时和冬令时的切换。\\n6. 事件记录：T2000能够记录事件，并提供查看和打印事件记录的功能。\\n7. 故障处理：在发生故障时，系统会有相应的反应，并提供故障处理指南。\\n8. 维护功能：系统提供了维护请求、测试蓄电池、查看火警总数等维护功能。\\n9. 网络功能：T2000支持组网，可以与其他火警控制器和复示器联网工作。\\n10. 电源单元：集成的电源单元可以为非寻址设备接口模块、报警器、门释放装置和复示器等设备供电。\\n\\n此外，T2000火警控制器还使用了先进的泰科MX TechnologyTM技术，满足多项国际标准，在船运和海洋石油领域得到了广泛应用。[ID:2]\\n\\n请注意，上述功能的详细操作和设置请参照T2000的操作手册，确保正确和安全地使用系统。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 14:15:38\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统，它集成了多种功能，包括但不限于以下几项：\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 事件监控：T2000能够监控火警事件，并在发生火警时提供及时的报警响应。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 显示功能：系统配备了液晶显示器，可以显示火警窗口、状态窗口、主窗口以及软键窗口等，用于显示各种系统状态和警告信息。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 控制器操作：T2000允许操作者通过控制器进行事件监控、事件显示以及系统设置等操作。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. 多级用户权限：系统将操作功能分成了不同的级别，包括客户操作员、客户经理、工程师以及总工程师等，不同级别的用户登录后可以操作对应的功能。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"5. 时间/日期设置：操作者可以设置和调整系统的时间/日期，包括夏令时和冬令时的切换。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"6. 事件记录：T2000能够记录事件，并提供查看和打印事件记录的功能。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"7. 故障处理：在发生故障时，系统会有相应的反应，并提供故障处理指南。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"8. 维护功能：系统提供了维护请求、测试蓄电池、查看火警总数等维护功能。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"9. 网络功能：T2000支持组网，可以与其他火警控制器和复示器联网工作。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"10. 电源单元：集成的电源单元可以为非寻址设', '[{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 10:12:54\",\"id\":82,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"39de672e57b311f0baec0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000能做啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 14:15:39\",\"id\":85,\"params\":{},\"role\":\"user\",\"sessionId\":\"39de672e57b311f0baec0242ac120006\"},{\"chatId\":\"0d8e9222554f11f0ad790242ac120006\",\"content\":\"T2000是一种数字寻址式火警探测和报警系统，它集成了多种功能，包括但不限于以下几项：[ID:0] [ID:1] [ID:2]\\n\\n1. 事件监控：T2000能够监控火警事件，并在发生火警时提供及时的报警响应。\\n2. 显示功能：系统配备了液晶显示器，可以显示火警窗口、状态窗口、主窗口以及软键窗口等，用于显示各种系统状态和警告信息。\\n3. 控制器操作：T2000允许操作者通过控制器进行事件监控、事件显示以及系统设置等操作。\\n4. 多级用户权限：系统将操作功能分成了不同的级别，包括客户操作员、客户经理、工程师以及总工程师等，不同级别的用户登录后可以操作对应的功能。\\n5. 时间/日期设置：操作者可以设置和调整系统的时间/日期，包括夏令时和冬令时的切换。\\n6. 事件记录：T2000能够记录事件，并提供查看和打印事件记录的功能。\\n7. 故障处理：在发生故障时，系统会有相应的反应，并提供故障处理指南。\\n8. 维护功能：系统提供了维护请求、测试蓄电池、查看火警总数等维护功能。\\n9. 网络功能：T2000支持组网，可以与其他火警控制器和复示器联网工作。\\n10. 电源单元：集成的电源单元可以为非寻址设备接口模块、报警器、门释放装置和复示器等设备供电。\\n\\n此外，T2000火警控制器还使用了先进的泰科MX TechnologyTM技术，满足多项国际标准，在船运和海洋石油领域得到了广泛应用。[ID:2]\\n\\n请注意，上述功能的详细操作和设置请参照T2000的操作手册，确保正确和安全地使用系统。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-03 14:15:39\",\"id\":86,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"T2000是一种数字寻址式火警探测和报警系统，它集成了多种功能，包括但不限于以下几项：\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":0},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\