INSERT INTO `sys_oper_log` VALUES (530, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/session', '192.168.1.101', '内网IP', '{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:37\",\"id\":48,\"params\":{},\"sessionId\":\"606f0fc058a711f09ae10242ac120006\",\"sessionName\":\"typescript有啥优势\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:37\",\"id\":48,\"params\":{},\"sessionId\":\"606f0fc058a711f09ae10242ac120006\",\"sessionName\":\"typescript有啥优势\"}}', 0, NULL, '2025-07-04 07:20:35', 304);
INSERT INTO `sys_oper_log` VALUES (531, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript有啥优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:57\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"606f0fc058a711f09ae10242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"TypeScript 相比 JavaScript 具有以下优势：\\n\\n1. **静态类型检查**：TypeScript 提供了静态类型系统，可以在编译阶段捕获潜在的类型错误，减少运行时错误 ##0$$。例如，可以明确声明变量类型（如 `let age: number`），避免意外的类型转换问题。\\n\\n2. **更适合大型项目**：随着代码量增长（如几万行甚至十几万行），TypeScript 的类型系统和清晰的结构能显著提升代码可维护性 ##0$$ ##2$$。其接口（`interface`）、泛型等功能帮助开发者更好地组织复杂逻辑。\\n\\n3. **现代开发特性支持**：\\n   - **泛型**：允许编写可复用的类型安全组件（如 `class Person<T>`）##7$$。\\n   - **高级类型**：提供联合类型、字面量类型（如 `let a: \'你好\'`）、元组等，增强代码表达能力 ##5$$。\\n   - **抽象类与接口**：支持面向对象编程的进阶特性（如抽象方法、属性修饰符）##1$$。\\n\\n4. **兼容性与工具链**：\\n   - TypeScript 是 JavaScript 的超集，完全兼容现有 JS 代码 ##6$$。\\n   - 可通过 `.d.ts` 声明文件为旧 JS 库添加类型支持，提升开发体验 ##3$$。\\n\\n5. **编译时优化**：需编译为 JavaScript 运行，但自动化编译工具（如 `tsc --init`）简化了这一流程 ##4$$。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:57\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 相比 JavaScript 具有以下优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **静态类型检查**：TypeScript 提供了静态类型系统，可以在编译阶段捕获潜在的类型错误，减少运行时错误 ##0$$。例如，可以明确声明变量类型（如 `let age: number`），避免意外的类型转换问题。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **更适合大型项目**：随着代码量增长（如几万行甚至十几万行），TypeScript 的类型系统和清晰的结构能显著提升代码可维护性 ##0$$ ##2$$。其接口（`interface`）、泛型等功能帮助开发者更好地组织复杂逻辑。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **现代开发特性支持**：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - **泛型**：允许编写可复用的类型安全组件（如 `class Person<T>`）##7$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - **高级类型**：提供联合类型、字面量类型（如 `let a: \'你好\'`）、元组等，增强代码表达能力 ##5$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - **抽象类与接口**：支持面向对象编程的进阶特性（如抽象方法、属性修饰符）##1$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **兼容性与工具链**：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - TypeScript 是 JavaScript 的超集，完全兼容现有 JS 代码 ##6$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 可通过 `.d.ts` 声明文件为旧 JS 库添加类型支持，提升开发体验 ##3$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:37\",\"id\":87,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"606f0fc058a711f09ae10242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript有啥优势\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:58\",\"id\":88,\"params\":{},\"role\":\"user\",\"sessionId\":\"606f0fc058a711f09ae10242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"TypeScript 相比 JavaScript 具有以下优势：\\n\\n1. **静态类型检查**：TypeScript 提供了静态类型系统，可以在编译阶段捕获潜在的类型错误，减少运行时错误 ##0$$。例如，可以明确声明变量类型（如 `let age: number`），避免意外的类型转换问题。\\n\\n2. **更适合大型项目**：随着代码量增长（如几万行甚至十几万行），TypeScript 的类型系统和清晰的结构能显著提升代码可维护性 ##0$$ ##2$$。其接口（`interface`）、泛型等功能帮助开发者更好地组织复杂逻辑。\\n\\n3. **现代开发特性支持**：\\n   - **泛型**：允许编写可复用的类型安全组件（如 `class Person<T>`）##7$$。\\n   - **高级类型**：提供联合类型、字面量类型（如 `let a: \'你好\'`）、元组等，增强代码表达能力 ##5$$。\\n   - **抽象类与接口**：支持面向对象编程的进阶特性（如抽象方法、属性修饰符）##1$$。\\n\\n4. **兼容性与工具链**：\\n   - TypeScript 是 JavaScript 的超集，完全兼容现有 JS 代码 ##6$$。\\n   - 可通过 `.d.ts` 声明文件为旧 JS 库添加类型支持，提升开发体验 ##3$$。\\n\\n5. **编译时优化**：需编译为 JavaScript 运行，但自动化编译工具（如 `tsc --init`）简化了这一流程 ##4$$。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:20:58\",\"id\":89,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 相比 JavaScript 具有以下优势：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **静态类型检查**：TypeScript 提供了静态类型系统，可以在编译阶段捕获潜在的类型错误，减少运行时错误 ##0$$。例如，可以明确声明变量类型（如 `let age: number`），避免意外的类型转换问题。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **更适合大型项目**：随着代码量增长（如几万行甚至十几万行），TypeScript 的类型系统和清晰的结构能显著提升代码可维护性 ##0$$ ##2$$。其接口（`interface`）、泛型等功能帮助开发者更好地组织复杂逻辑。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **现代开发特性支持**：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - **泛型**：允许编写可复用的类型安全组件（如 `class Person<T>`）##7$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - **高级类型**：提供联合类型、字面量类型（如 `let a: \'你好\'`）、元组等，增强代码表达能力 ##5$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - **抽象类与接口**：支持面向对象编程的进阶特性（如抽象方法、属性修饰符）##1$$。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **兼容性与工具链**：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\', 0, NULL, '2025-07-04 07:20:55', 181);
INSERT INTO `sys_oper_log` VALUES (532, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/session', '192.168.1.101', '内网IP', '{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:50\",\"id\":49,\"params\":{},\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\",\"sessionName\":\"请查询操作手册\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:50\",\"id\":49,\"params\":{},\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\",\"sessionName\":\"请查询操作手册\"}}', 0, NULL, '2025-07-04 07:21:48', 256);
INSERT INTO `sys_oper_log` VALUES (533, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\n\\n1. **火警显示功能**  \\n   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\n   - 出现火警时显示\\\"第一个火警(FIRST FIRE)\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\n\\n2. **事件优先级与处理**  \\n   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\n   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\n\\n3. **控制器功能菜单**  \\n   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\n   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\n\\n4. **故障处理流程**  \\n   - 故障时蜂鸣器间断鸣响，\\\"通用故障\\\"黄灯亮起，LCD显示故障区/点位置及类型描述 ##7$$。  \\n   - 需先消声后排查原因，故障信息会持续显示直至解除或人工确认 ##7$$。  \\n\\n如需特定功能的详细操作步骤（如时间设置或打印记录），请进一步说明具体需求。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警显示功能**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 出现火警时显示\\\\\\\"第一个火警(FIRST FIRE)\\\\\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件优先级与处理**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **控制器功能菜单**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **故障处理流程**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 故障时蜂鸣器间断鸣响，\\\\\\\"通用故障\\\\\\\"黄灯亮起，LCD显示故障区/点位置及类型描述 ##7$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 需先消声后排查原因，故障信息会持续显示直至解除或人工确认 ##7$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"如需特定功能的详细操作步', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:51\",\"id\":90,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"id\":91,\"params\":{},\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\n\\n1. **火警显示功能**  \\n   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\n   - 出现火警时显示\\\"第一个火警(FIRST FIRE)\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\n\\n2. **事件优先级与处理**  \\n   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\n   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\n\\n3. **控制器功能菜单**  \\n   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\n   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\n\\n4. **故障处理流程**  \\n   - 故障时蜂鸣器间断鸣响，\\\"通用故障\\\"黄灯亮起，LCD显示故障区/点位置及类型描述 ##7$$。  \\n   - 需先消声后排查原因，故障信息会持续显示直至解除或人工确认 ##7$$。  \\n\\n如需特定功能的详细操作步骤（如时间设置或打印记录），请进一步说明具体需求。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"id\":92,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警显示功能**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 出现火警时显示\\\\\\\"第一个火警(FIRST FIRE)\\\\\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件优先级与处理**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **控制器功能菜单**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **故障处理流程**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 故障时蜂鸣器间断', 0, NULL, '2025-07-04 07:22:10', 177);
INSERT INTO `sys_oper_log` VALUES (534, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:29:43\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\n\\n1. **火警显示功能**  \\n   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\n   - 出现火警时显示\\\"第一个火警(FIRST FIRE)\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息（如图表所示具体楼层和房间位置）##6$$。  \\n\\n2. **事件优先级与处理**  \\n   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息##2$$。  \\n   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态##7$$。  \\n\\n3. **控制器功能菜单**  \\n   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块##3$$。  \\n   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码##3$$。  \\n\\n4. **故障处理流程**  \\n   - 故障时蜂鸣器间断鸣响，\\\"通用故障\\\"黄灯亮起，LCD显示故障区/点位置及类型描述##7$$。  \\n   - 需先消声后排查原因，故障信息会持续显示直至解除或人工确认##7$$。\\n\\n5. **日常维护功能**\\n- 可查看火警总数和维护请求\\n- 支持蓄电池测试和软件版本查询\\n- 提供项目号和菜单点管理功能\\n\\n如需特定功能的详细操作步骤（如时间设置或打印记录），请进一步说明具体需求。##0$$\\n\\n注：NF-8型号的操作要求（如防尘防潮环境）未在T2000手册中体现，若需混合机型指导请明确说明。##4$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:29:43\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警显示功能**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 正常状态下火警窗口显示产品名、日期/时间和公司名 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 出现火警时显示\\\\\\\"第一个火警(FIRST FIRE)\\\\\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息（如图表所示具体楼层和房间位置）\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件优先级与处理**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **控制器功能菜单**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块\\\"},{\\\"type\\', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:51\",\"id\":90,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"id\":91,\"params\":{},\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\n\\n1. **火警显示功能**  \\n   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\n   - 出现火警时显示\\\"第一个火警(FIRST FIRE)\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\n\\n2. **事件优先级与处理**  \\n   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\n   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\n\\n3. **控制器功能菜单**  \\n   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\n   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\n\\n4. **故障处理流程**  \\n   - 故障时蜂鸣器间断鸣响，\\\"通用故障\\\"黄灯亮起，LCD显示故障区/点位置及类型描述 ##7$$。  \\n   - 需先消声后排查原因，故障信息会持续显示直至解除或人工确认 ##7$$。  \\n\\n如需特定功能的详细操作步骤（如时间设置或打印记录），请进一步说明具体需求。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"id\":92,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警显示功能**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 出现火警时显示\\\\\\\"第一个火警(FIRST FIRE)\\\\\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件优先级与处理**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **控制器功能菜单**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **故障处理流程**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 故障时蜂鸣器间断', 0, NULL, '2025-07-04 07:29:41', 183);
