INSERT INTO `sys_oper_log` VALUES (541, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 16:26:42\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"以下是基于知识库中T2000火警系统操作手册的详细功能说明：\\n\\n1. 系统基础信息\\n- T2000是泰科公司\\\"MX\\\"系列数字寻址式火警控制器\\n- 最多支持4个回路(每回路250个设备)或8个回路(每回路125个设备)\\n- 可连接7个全功能复示器和遥控打印机 ##5$$\\n\\n2. 主要显示区域\\n2.1 火警窗口：\\n- 正常状态：显示产品名、日期/时间和公司名\\n- 报警状态：显示首个火警位置(如\\\"1st Floor Corridoor\\\")和末次火警信息 ##6$$\\n2.2 状态窗口：\\n实时显示系统故障总数和隔离总数 ##1$$\\n\\n3. 核心操作功能\\n3.1 事件处理：\\n- 优先级：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##2$$\\n3.2 故障响应：\\n- \\\"通用故障\\\"黄灯亮起，蜂鸣器间断鸣响\\n- LCD显示故障详情(区域/地址/类型描述) ##7$$\\n\\n4. 管理功能菜单\\n4.1 用户权限：\\n- 分5级权限(操作员/经理/工程师等)\\n- 工程师需7位密码，总工程师需8位密码 ##3$$\\n4.2维护功能：\\n-蓄电池测试 \\n-软件版本查询 \\n-项目号管理##0$$\\n\\n5.特殊注意事项\\n5.1预报警处理：\\n必须确认地点和原因，可能升级为真实火警##7$$\\n5.2复位要求：\\n多个事件需按优先级顺序处理##2$$\\n\\n注：如需具体操作指导（如时间设置步骤或打印记录方法），请告知需要查询的具体章节。本回复未包含NF-8型号相关内容。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 16:26:42\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以下是基于知识库中T2000火警系统操作手册的详细功能说明：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 系统基础信息\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- T2000是泰科公司\\\\\\\"MX\\\\\\\"系列数字寻址式火警控制器\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 最多支持4个回路(每回路250个设备)或8个回路(每回路125个设备)\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 可连接7个全功能复示器和遥控打印机 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 主要显示区域\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2.1 火警窗口：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 正常状态：显示产品名、日期/时间和公司名\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 报警状态：显示首个火警位置(如\\\\\\\"1st Floor Corridoor\\\\\\\")和末次火警信息 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2.2 状态窗口：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"实时显示系统故障总数和隔离总数 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. 核心操作功能\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3.1 事件处理：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 优先级：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":null}],[{\\\"type\\\":\\', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:51\",\"id\":90,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"id\":91,\"params\":{},\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\n\\n1. **火警显示功能**  \\n   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\n   - 出现火警时显示\\\"第一个火警(FIRST FIRE)\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\n\\n2. **事件优先级与处理**  \\n   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\n   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\n\\n3. **控制器功能菜单**  \\n   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\n   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\n\\n4. **故障处理流程**  \\n   - 故障时蜂鸣器间断鸣响，\\\"通用故障\\\"黄灯亮起，LCD显示故障区/点位置及类型描述 ##7$$。  \\n   - 需先消声后排查原因，故障信息会持续显示直至解除或人工确认 ##7$$。  \\n\\n如需特定功能的详细操作步骤（如时间设置或打印记录），请进一步说明具体需求。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:22:13\",\"id\":92,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"根据知识库中的T2000中文操作手册内容，以下是相关功能的详细说明：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **火警显示功能**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 正常状态下火警窗口显示产品名、日期/时间和公司名 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 出现火警时显示\\\\\\\"第一个火警(FIRST FIRE)\\\\\\\"及回路/地址/位置信息，多火警时会同时显示首尾两个火警信息 ##1$$ ##6$$（如图表所示具体楼层和房间位置）。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **事件优先级与处理**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 事件优先级排序：火警＞预报警＞故障＞隔离＞测试模式＞警告＞信息 ##1$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 预报警需先确认地点和原因，若后续转为火警则系统自动升级状态 ##7$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **控制器功能菜单**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 包含主菜单、事件确认、状态查看、隔离操作、时间设置等模块 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 支持按用户级别（客户操作员/经理/工程师等）限制功能访问，工程师级需7-8位密码 ##3$$。  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"4. **故障处理流程**  \\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"   - 故障时蜂鸣器间断', 0, NULL, '2025-07-04 08:26:40', 189);
