INSERT INTO `sys_oper_log` VALUES (545, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门11', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 16:28:45\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"以下是基于知识库中T2000火警系统操作手册的详细功能说明（包含具体操作步骤）：\\n\\n1. 系统基础配置\\n- 控制器型号：T2000数字寻址式火警控制器\\n- 最大容量：\\n  • 4回路×250设备或8回路×125设备\\n  • 支持7个全功能复示器+遥控打印机##5$$\\n- 通信功能：可通过电话网远程监控##5$$\\n\\n2. 日常操作流程\\n2.1 登录系统：\\n- 插入钥匙至\\\"I\\\"位置=客户操作员1级(免密码)##3$$\\n- 高级权限需输入对应位数密码(工程师7位/总工程师8位)##3$$\\n\\n2.2 事件处理步骤：\\n①火警确认：\\n- LCD自动显示首个报警点位置(如\\\"4th Floor Washroom/Window\\\")##6$$\\n- 按[Accept Events]软键确认事件##3$$\\n\\n②故障处理：\\n1)按[SILENCE BUZZER]键消声##7$$\\n2)检查LCD显示的故障详情(含区域代码和设备类型)##7$$\\n\\n3. 专业功能操作\\n3.1隔离设备：\\n路径：主菜单→Isolate/De-isolate→选择回路/地址##0$$\\n\\n3.2设置时间：\\n路径：Time/Date→Set Time/Date→输入新时间(格式HH:MM)##0$$\\n\\n4.维护管理\\n4.1查看记录：\\n-事件记录可过滤显示/打印##0$$\\n-支持按日期查询历史报警##0$$\\n\\n4.2电池测试：\\n路径：Service→Maintenance→Test Batteries##0$$\\n\\n5.注意事项\\n•预报警必须人工确认位置和原因，可能升级为真实火警##7$$\\n•复位前需确保所有事件已处理完毕##2$$ \\n\\n如需特定功能的图文指引（如火警窗口界面详解），请告知具体需求。注：NF-8型号相关内容不在本回复范围内。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 16:28:45\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以下是基于知识库中T2000火警系统操作手册的详细功能说明（包含具体操作步骤）：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 系统基础配置\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 控制器型号：T2000数字寻址式火警控制器\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 最大容量：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"  • 4回路×250设备或8回路×125设备\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"  • 支持7个全功能复示器+遥控打印机\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 通信功能：可通过电话网远程监控\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 日常操作流程\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2.1 登录系统：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 插入钥匙至\\\\\\\"I\\\\\\\"位置=客户操作员1级(免密码)\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 高级权限需输入对应位数密码(工程师7位/总工程师8位)\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2.2 事件处理步骤：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\"', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:51\",\"id\":90,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 16:28:46\",\"id\":97,\"params\":{},\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"以下是基于知识库中T2000火警系统操作手册的详细功能说明（包含具体操作步骤）：\\n\\n1. 系统基础配置\\n- 控制器型号：T2000数字寻址式火警控制器\\n- 最大容量：\\n  • 4回路×250设备或8回路×125设备\\n  • 支持7个全功能复示器+遥控打印机##5$$\\n- 通信功能：可通过电话网远程监控##5$$\\n\\n2. 日常操作流程\\n2.1 登录系统：\\n- 插入钥匙至\\\"I\\\"位置=客户操作员1级(免密码)##3$$\\n- 高级权限需输入对应位数密码(工程师7位/总工程师8位)##3$$\\n\\n2.2 事件处理步骤：\\n①火警确认：\\n- LCD自动显示首个报警点位置(如\\\"4th Floor Washroom/Window\\\")##6$$\\n- 按[Accept Events]软键确认事件##3$$\\n\\n②故障处理：\\n1)按[SILENCE BUZZER]键消声##7$$\\n2)检查LCD显示的故障详情(含区域代码和设备类型)##7$$\\n\\n3. 专业功能操作\\n3.1隔离设备：\\n路径：主菜单→Isolate/De-isolate→选择回路/地址##0$$\\n\\n3.2设置时间：\\n路径：Time/Date→Set Time/Date→输入新时间(格式HH:MM)##0$$\\n\\n4.维护管理\\n4.1查看记录：\\n-事件记录可过滤显示/打印##0$$\\n-支持按日期查询历史报警##0$$\\n\\n4.2电池测试：\\n路径：Service→Maintenance→Test Batteries##0$$\\n\\n5.注意事项\\n•预报警必须人工确认位置和原因，可能升级为真实火警##7$$\\n•复位前需确保所有事件已处理完毕##2$$ \\n\\n如需特定功能的图文指引（如火警窗口界面详解），请告知具体需求。注：NF-8型号相关内容不在本回复范围内。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 16:28:46\",\"id\":98,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以下是基于知识库中T2000火警系统操作手册的详细功能说明（包含具体操作步骤）：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 系统基础配置\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 控制器型号：T2000数字寻址式火警控制器\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 最大容量：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"  • 4回路×250设备或8回路×125设备\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"  • 支持7个全功能复示器+遥控打印机\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 通信功能：可通过电话网远程监控\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. 日常操作流程\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2.1 登录系统：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 插入钥匙至\\\\\\\"I\\\\\\\"位置=客户操作员1级(免密码)\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":3}]', 0, NULL, '2025-07-04 08:28:43', 161);
