INSERT INTO `sys_oper_log` VALUES (588, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'system', '研发部门1', '/aftersales/chat', '124.234.158.110', 'XX XX', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"system\",\"createTime\":\"2025-07-04 18:17:22\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"以下是T2000火警系统操作手册的详细内容整理，包含具体功能说明和操作步骤：\\n\\n1. 系统概述 ##5$$ ##1$$ ##7$$\\n- 型号：T2000数字寻址式火警控制器（泰科MX系列） ##2$$\\n- 容量配置：\\n  • 最大4回路×250设备或8回路×125设备\\n  • 支持7个全功能复示器+遥控打印机\\n- 远程监控：可通过\\\"MX-Remote\\\"软件实现远程诊断\\n\\n2. 基本操作流程\\n2.1 用户登录：\\n- 【钥匙位置】：\\n  普通操作：\\\"I\\\"位置（免密码）\\n  高级设置：\\\"ENABLE\\\"位置\\n- 【密码权限】：\\n  客户经理：5-6位\\n  工程师：7位  ##3$$\\n  总工程师：8位\\n\\n2.2 报警处理：\\n①火警响应：\\n1) LCD自动高亮显示报警点信息（含楼层/房间号）\\n2) 按[FIRE ALARM]键确认声光报警\\n3) 通过软键[Accept Events]记录事件\\n\\n②故障处理：\\n1)按面板[SILENCE BUZZER]键停止蜂鸣器 \\n2)查看LCD显示的故障详情（示例格式）：\\n--------------------------------- ##4$$ ##6$$\\nZone:002 R10  \\nLocation:System Zone  \\nPoint:Battery Fault IP  \\nType:Power Supply Failure  \\n---------------------------------\\n\\n3.专业功能操作指南\\n3.1设备隔离：【主菜单】→【Isolate】\\n→选择回路号→输入地址→确认隔离\\n\\n3.2时间设置：【Time/Date】→【Set】\\n→使用数字键盘输入当前时间（24小时制）\\n\\n4.维护管理功能\\n4.1记录查询：【Event Log】可：\\n•按日期筛选事件 \\n•打印特定时段记录 \\n•查看未测试设备清单\\n\\n4.2系统检测：【Service】菜单包含：\\n•蓄电池电压测试 \\n•软件版本核查  ##0$$\\n•回路设备总数统计 \\n\\n5.重要注意事项\\n★预报警必须执行以下步骤：\\n1)立即确认报警点物理位置 \\n2)检查环境状况（温度/烟雾等）\\n3)如确认为误报需手动复位\\n\\n★多事件处理原则：严格按优先级顺序处置，火警>故障>警告 \\n\\n注：本回复基于T2000中文操作手册整理，如需NF-8型号内容请另行说明。特定功能的图文详解可提供更详细的操作指引。\",\"createBy\":\"system\",\"createTime\":\"2025-07-04 18:17:22\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以下是T2000火警系统操作手册的详细内容整理，包含具体功能说明和操作步骤：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 系统概述 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 型号：T2000数字寻址式火警控制器（泰科MX系列） \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 容量配置：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"  • 最大4回路×250设备或8回路×125设备\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"  • 支持7个全功能复示器+遥控打印机\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 远程监控：可通过\\\\\\\"MX-Remote\\\\\\\"软件实现', '[{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-04 15:21:51\",\"id\":90,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"请查询操作手册\",\"createBy\":\"system\",\"createTime\":\"2025-07-04 18:17:23\",\"id\":101,\"params\":{},\"role\":\"user\",\"sessionId\":\"8c26ebf658a711f0ace20242ac120006\"},{\"chatId\":\"6e60e36658a611f084cb0242ac120006\",\"content\":\"以下是T2000火警系统操作手册的详细内容整理，包含具体功能说明和操作步骤：\\n\\n1. 系统概述 ##5$$ ##1$$ ##7$$\\n- 型号：T2000数字寻址式火警控制器（泰科MX系列） ##2$$\\n- 容量配置：\\n  • 最大4回路×250设备或8回路×125设备\\n  • 支持7个全功能复示器+遥控打印机\\n- 远程监控：可通过\\\"MX-Remote\\\"软件实现远程诊断\\n\\n2. 基本操作流程\\n2.1 用户登录：\\n- 【钥匙位置】：\\n  普通操作：\\\"I\\\"位置（免密码）\\n  高级设置：\\\"ENABLE\\\"位置\\n- 【密码权限】：\\n  客户经理：5-6位\\n  工程师：7位  ##3$$\\n  总工程师：8位\\n\\n2.2 报警处理：\\n①火警响应：\\n1) LCD自动高亮显示报警点信息（含楼层/房间号）\\n2) 按[FIRE ALARM]键确认声光报警\\n3) 通过软键[Accept Events]记录事件\\n\\n②故障处理：\\n1)按面板[SILENCE BUZZER]键停止蜂鸣器 \\n2)查看LCD显示的故障详情（示例格式）：\\n--------------------------------- ##4$$ ##6$$\\nZone:002 R10  \\nLocation:System Zone  \\nPoint:Battery Fault IP  \\nType:Power Supply Failure  \\n---------------------------------\\n\\n3.专业功能操作指南\\n3.1设备隔离：【主菜单】→【Isolate】\\n→选择回路号→输入地址→确认隔离\\n\\n3.2时间设置：【Time/Date】→【Set】\\n→使用数字键盘输入当前时间（24小时制）\\n\\n4.维护管理功能\\n4.1记录查询：【Event Log】可：\\n•按日期筛选事件 \\n•打印特定时段记录 \\n•查看未测试设备清单\\n\\n4.2系统检测：【Service】菜单包含：\\n•蓄电池电压测试 \\n•软件版本核查  ##0$$\\n•回路设备总数统计 \\n\\n5.重要注意事项\\n★预报警必须执行以下步骤：\\n1)立即确认报警点物理位置 \\n2)检查环境状况（温度/烟雾等）\\n3)如确认为误报需手动复位\\n\\n★多事件处理原则：严格按优先级顺序处置，火警>故障>警告 \\n\\n注：本回复基于T2000中文操作手册整理，如需NF-8型号内容请另行说明。特定功能的图文详解可提供更详细的操作指引。\",\"createBy\":\"system\",\"createTime\":\"2025-07-04 18:17:23\",\"id\":102,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"以下是T2000火警系统操作手册的详细内容整理，包含具体功能说明和操作步骤：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. 系统概述 \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":5},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":7}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 型号：T2000数字寻址式火警控制器（泰科MX系列） \\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"- 容量配置：\\\"}],[{\\\"t', 0, NULL, '2025-07-04 10:17:23', 296);
