INSERT INTO `sys_oper_log` VALUES (600, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 16:36:10\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"搜索中...\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 16:36:10\",\"messageId\":\"\",\"packageContent\":\"\\\"\\\"\",\"params\":{},\"reference\":\"\\\"\\\"\",\"role\":\"assistant\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"}]', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:33\",\"id\":104,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:46\",\"id\":105,\"params\":{},\"role\":\"user\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"TypeScript 是一种由微软开发的编程语言，它是基于 JavaScript 的一个扩展语言，属于 JavaScript 的超集（即包含 JavaScript 的所有内容）##2$$。它主要增加了静态类型检查、接口、泛型等现代开发特性，使其更适合大型项目的开发##1$$ ##4$$。\\n\\nTypeScript 需要通过编译转换为 JavaScript，才能在浏览器或其他 JavaScript 运行环境中执行##2$$ ##4$$。它的优势包括：\\n1. **类型系统**：提供静态类型检查，减少运行时错误。\\n2. **更好的工具支持**：如代码补全、接口提示等。\\n3. **适合大型项目**：代码结构更清晰，便于维护##1$$ ##4$$。\\n\\n总结来说，TypeScript 是增强版的 JavaScript，尤其适合复杂应用的开发。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:46\",\"id\":106,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 是一种由微软开发的编程语言，它是基于 JavaScript 的一个扩展语言，属于 JavaScript 的超集（即包含 JavaScript 的所有内容）\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它主要增加了静态类型检查、接口、泛型等现代开发特性，使其更适合大型项目的开发\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 需要通过编译转换为 JavaScript，才能在浏览器或其他 JavaScript 运行环境中执行\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它的优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **类型系统**：提供静态类型检查，减少运行时错误。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **更好的工具支持**：如代码补全、接口提示等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **适合大型项目**：代码结构更清晰，便于维护\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"总结来说，TypeScript 是增强版的 JavaScript，尤其适合复杂应用的开发。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\', 0, NULL, '2025-07-07 08:36:10', 269);
INSERT INTO `sys_oper_log` VALUES (601, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 16:36:25\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"搜索中...\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 16:36:25\",\"messageId\":\"\",\"packageContent\":\"\\\"\\\"\",\"params\":{},\"reference\":\"\\\"\\\"\",\"role\":\"assistant\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"}]', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:33\",\"id\":104,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:46\",\"id\":105,\"params\":{},\"role\":\"user\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"TypeScript 是一种由微软开发的编程语言，它是基于 JavaScript 的一个扩展语言，属于 JavaScript 的超集（即包含 JavaScript 的所有内容）##2$$。它主要增加了静态类型检查、接口、泛型等现代开发特性，使其更适合大型项目的开发##1$$ ##4$$。\\n\\nTypeScript 需要通过编译转换为 JavaScript，才能在浏览器或其他 JavaScript 运行环境中执行##2$$ ##4$$。它的优势包括：\\n1. **类型系统**：提供静态类型检查，减少运行时错误。\\n2. **更好的工具支持**：如代码补全、接口提示等。\\n3. **适合大型项目**：代码结构更清晰，便于维护##1$$ ##4$$。\\n\\n总结来说，TypeScript 是增强版的 JavaScript，尤其适合复杂应用的开发。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:46\",\"id\":106,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 是一种由微软开发的编程语言，它是基于 JavaScript 的一个扩展语言，属于 JavaScript 的超集（即包含 JavaScript 的所有内容）\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它主要增加了静态类型检查、接口、泛型等现代开发特性，使其更适合大型项目的开发\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 需要通过编译转换为 JavaScript，才能在浏览器或其他 JavaScript 运行环境中执行\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它的优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **类型系统**：提供静态类型检查，减少运行时错误。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **更好的工具支持**：如代码补全、接口提示等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **适合大型项目**：代码结构更清晰，便于维护\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"总结来说，TypeScript 是增强版的 JavaScript，尤其适合复杂应用的开发。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\', 0, NULL, '2025-07-07 08:36:25', 139);
INSERT INTO `sys_oper_log` VALUES (602, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 16:36:48\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"搜索中...\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 16:36:49\",\"messageId\":\"\",\"packageContent\":\"\\\"\\\"\",\"params\":{},\"reference\":\"\\\"\\\"\",\"role\":\"assistant\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"}]', '[{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:33\",\"id\":104,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:46\",\"id\":105,\"params\":{},\"role\":\"user\",\"sessionId\":\"af810c085b0411f08e520242ac120006\"},{\"chatId\":\"533f761e58a711f0a34c0242ac120006\",\"content\":\"TypeScript 是一种由微软开发的编程语言，它是基于 JavaScript 的一个扩展语言，属于 JavaScript 的超集（即包含 JavaScript 的所有内容）##2$$。它主要增加了静态类型检查、接口、泛型等现代开发特性，使其更适合大型项目的开发##1$$ ##4$$。\\n\\nTypeScript 需要通过编译转换为 JavaScript，才能在浏览器或其他 JavaScript 运行环境中执行##2$$ ##4$$。它的优势包括：\\n1. **类型系统**：提供静态类型检查，减少运行时错误。\\n2. **更好的工具支持**：如代码补全、接口提示等。\\n3. **适合大型项目**：代码结构更清晰，便于维护##1$$ ##4$$。\\n\\n总结来说，TypeScript 是增强版的 JavaScript，尤其适合复杂应用的开发。\",\"createBy\":\"admin\",\"createTime\":\"2025-07-07 15:33:46\",\"id\":106,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 是一种由微软开发的编程语言，它是基于 JavaScript 的一个扩展语言，属于 JavaScript 的超集（即包含 JavaScript 的所有内容）\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它主要增加了静态类型检查、接口、泛型等现代开发特性，使其更适合大型项目的开发\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"TypeScript 需要通过编译转换为 JavaScript，才能在浏览器或其他 JavaScript 运行环境中执行\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":2},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。它的优势包括：\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"1. **类型系统**：提供静态类型检查，减少运行时错误。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"2. **更好的工具支持**：如代码补全、接口提示等。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"3. **适合大型项目**：代码结构更清晰，便于维护\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":1},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":4},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"。\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"总结来说，TypeScript 是增强版的 JavaScript，尤其适合复杂应用的开发。\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\', 0, NULL, '2025-07-07 08:36:48', 162);
