INSERT INTO `sys_oper_log` VALUES (661, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '36.48.10.86', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你是谁\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 09:53:11\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"anedrb6zosdfc0tvcqx4pkstcezq2tbu\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"搜索中...\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 09:53:11\",\"messageId\":\"\",\"packageContent\":\"\\\"\\\"\",\"params\":{},\"reference\":\"\\\"\\\"\",\"role\":\"assistant\",\"sessionId\":\"anedrb6zosdfc0tvcqx4pkstcezq2tbu\"}]', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-09 15:57:46\",\"id\":145,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"anedrb6zosdfc0tvcqx4pkstcezq2tbu\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript\",\"createBy\":\"admin\",\"createTime\":\"2025-07-09 15:58:00\",\"id\":146,\"params\":{},\"role\":\"user\",\"sessionId\":\"anedrb6zosdfc0tvcqx4pkstcezq2tbu\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，即 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。浏览器不能直接运行 TypeScript 代码，需要将其编译为 JavaScript 后再由浏览器解析器执行。编译 TypeScript 的步骤包括：创建 TypeScript 文件（如 demo.ts），全局安装 TypeScript（使用 npm i typescript -g），然后使用命令 tsc demo.ts 进行编译。此外，TypeScript 还支持自动化编译，通过创建 TypeScript 编译控制文件（tsc --init）来实现。TypeScript 的类型声明文件（通常以 .d.ts 作为扩展名）为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。##0$$ ##1$$ ##2$$ ##4$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-09 15:58:00\",\"id\":147,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，即 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。浏览器不能直接运行 TypeScript 代码，需要将其编译为 JavaScript 后再由浏览器解析器执行。编译 TypeScript 的步骤包括：创建 TypeScript 文件（如 demo.ts），全局安装 TypeScript（使用 npm i typescript -g），然后使用命令 tsc demo.ts 进行编译。此外，TypeScript 还支持自动化编译，通过创建 TypeScript 编译控制文件（tsc --init）来实现。TypeScript 的类型声明文件（通常以 .d.ts 作为扩展名）为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"0\\\"},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"1\\\"},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"2\\\"},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"4\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型', 0, NULL, '2025-07-10 01:53:11', 81);
