INSERT INTO `sys_oper_log` VALUES (778, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'system', '研发部门1', '/aftersales/chat', '211.166.64.16', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好\",\"createBy\":\"system\",\"createTime\":\"2025-07-14 08:55:43\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！有什么问题我可以帮助你解答吗？\",\"createBy\":\"system\",\"createTime\":\"2025-07-14 08:55:43\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>你好！有什么问题我可以帮助你解答吗？</p>\\\\n\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":10,\\\"chunks\\\":[{\\\"id\\\":\\\"e456a344c72bdf49\\\",\\\"content\\\":\\\"tiany//以下代码，是将【原始类型】赋给a，有警告a =1  //警告：不能将类型“number”分配给类型“object”a =true  //警告：不能将类型“boolean”分配给类型“object”=\'你好\' //警告：不能将类型“string”分配给类型“object”a=null  //警告：不能将类型“null”分配给类型“object”a =undefined //警告：不能将类型“undefined”分配给类型“object”\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-e456a344c72bdf49\\\",\\\"positions\\\":[[15,85,451,289,378]],\\\"url\\\":null,\\\"similarity\\\":0.795638840067679,\\\"vector_similarity\\\":0.3187961335589303,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"063cc57d1ca25dd4\\\",\\\"content\\\":\\\"//以下代码，均⽆警告，因为给a赋的值，都是Object的实例对象b ={}b ={name:\'张三\'}b =[1,3,5,7,9]b =function(){}b =new String(\'123\')class Person {}b =new Person()b =1 //1不是Object的实例对象，但其包装对象是Object的实例b =true //truue不是Object的实例对象，但其包装对象是Object的实例b =\'你好\'//“你好”不是Object的实例对象，但其包装对象是Object的实例\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-063cc57d1ca25dd4\\\",\\\"positions\\\":[[16,85,478,180,344]],\\\"url\\\":null,\\\"similarity\\\":0.7931098839771635,\\\"vector_similarity\\\":0.31036627992387844,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"c2be253d50bb37e2\\\",\\\"content\\\":\\\"tianycodetianyatianyetianyatianyahdetianyetiany接⼝⾃动合并（可重复定义）//PersonInterface接⼝interface PersonInterfa', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 15:48:46\",\"id\":242,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"system\",\"createTime\":\"2025-07-10 17:08:55\",\"id\":258,\"params\":{},\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"system\",\"createTime\":\"2025-07-10 17:08:55\",\"id\":259,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"2\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.9123333734653447,\\\"vector_similarity\\\":0.7077779115511492,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. Typ', 0, NULL, '2025-07-14 00:55:43', 83);
INSERT INTO `sys_oper_log` VALUES (779, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'system', '研发部门1', '/aftersales/chat', '211.166.64.16', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"什么是因果循环\",\"createBy\":\"system\",\"createTime\":\"2025-07-14 08:56:05\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"知识库中未找到您要的答案！\",\"createBy\":\"system\",\"createTime\":\"2025-07-14 08:56:05\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>知识库中未找到您要的答案！</p>\\\\n\\\"}]]\",\"params\":{},\"reference\":\"{}\",\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"}]', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 15:48:46\",\"id\":242,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"system\",\"createTime\":\"2025-07-10 17:08:55\",\"id\":258,\"params\":{},\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"system\",\"createTime\":\"2025-07-10 17:08:55\",\"id\":259,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"2\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.9123333734653447,\\\"vector_similarity\\\":0.7077779115511492,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. Typ', 0, NULL, '2025-07-14 00:56:05', 94);
