\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.9123333734653447,\\\"vector_similarity\\\":0.7077779115511492,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. Typ', 0, NULL, '2025-07-17 08:48:48', 130);
INSERT INTO `sys_oper_log` VALUES (808, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '127.0.0.1', '内网IP', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript\",\"createBy\":\"admin\",\"createTime\":\"2025-07-17 16:49:07\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，因此 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。由于 TypeScript 的代码结构更加清晰，在后期代码的维护中，TypeScript 相较于 JavaScript 更胜一筹。浏览器不能直接运行 TypeScript 代码，需要将其编译为 JavaScript 后再由浏览器解析器执行。编译 TypeScript 的步骤包括：创建一个 .ts 文件，全局安装 TypeScript，然后使用命令编译 .ts 文件。此外，TypeScript 还支持自动化编译，通过创建 TypeScript 编译控制文件 tsc --init 来实现。##0$$ ##1$$ ##4$$ ##7$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-17 16:49:07\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，因此 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。由于 TypeScript 的代码结构更加清晰，在后期代码的维护中，TypeScript 相较于 JavaScript 更胜一筹。浏览器不能直接运行 TypeScript 代码，需要将其编译为 JavaScript 后再由浏览器解析器执行。编译 TypeScript 的步骤包括：创建一个 .ts 文件，全局安装 TypeScript，然后使用命令编译 .ts 文件。此外，TypeScript 还支持自动化编译，通过创建 TypeScript 编译控制文件 tsc --init 来实现。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"0\\\"},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"1\\\"},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"4\\\"},{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"7\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译