INSERT INTO `sys_oper_log` VALUES (820, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"介绍一下typescript\",\"createBy\":\"admin\",\"createTime\":\"2025-07-21 09:22:28\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3zawx9p6j7esmupkxjchvgubpn1n2o7g\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，因此 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript，然后交给浏览器或其他 JavaScript 运行环境执行。##3$$\\n\\nTypeScript 的主要作用是为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。类型声明文件是 TypeScript 中的一种特殊文件，通常以 .d.ts 作为扩展名。##2$$\\n\\nTypeScript 中的数据类型包括 JavaScript 中的所有类型，以及六个新类型：any、unknown、never、void、tuple、enum。此外，TypeScript 还提供了两种用于自定义类型的方式：type 和 interface。##9$$\\n\\nTypeScript 的代码量通常要大于 JavaScript，但由于 TypeScript 的代码结构更加清晰，在后期代码的维护中 TypeScript 却胜于 JavaScript。##1$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-21 09:22:28\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，因此 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript，然后交给浏览器或其他 JavaScript 运行环境执行。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"3\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 的主要作用是为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。类型声明文件是 TypeScript 中的一种特殊文件，通常以 .d.ts 作为扩展名。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"2\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 中的数据类型包括 JavaScript 中的所有类型，以及六个新类型：any、unknown、never、void、tuple、enum。此外，TypeScript 还提供了两种用于自定义类型的方式：type 和 interface。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"9\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 的代码量通常要大于 JavaScript，但由于 TypeScript 的代码结构更加清晰，在后期代码的维护中 TypeScript 却胜于 JavaScript。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"1\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":43,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 16:55:54\",\"id\":251,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3zawx9p6j7esmupkxjchvgubpn1n2o7g\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"介绍一下typescript\",\"createBy\":\"admin\",\"createTime\":\"2025-07-21 09:22:28\",\"id\":290,\"params\":{},\"role\":\"user\",\"sessionId\":\"3zawx9p6j7esmupkxjchvgubpn1n2o7g\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，因此 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript，然后交给浏览器或其他 JavaScript 运行环境执行。##3$$\\n\\nTypeScript 的主要作用是为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。类型声明文件是 TypeScript 中的一种特殊文件，通常以 .d.ts 作为扩展名。##2$$\\n\\nTypeScript 中的数据类型包括 JavaScript 中的所有类型，以及六个新类型：any、unknown、never、void、tuple、enum。此外，TypeScript 还提供了两种用于自定义类型的方式：type 和 interface。##9$$\\n\\nTypeScript 的代码量通常要大于 JavaScript，但由于 TypeScript 的代码结构更加清晰，在后期代码的维护中 TypeScript 却胜于 JavaScript。##1$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-21 09:22:28\",\"id\":291,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它包含了 JavaScript 的所有内容，因此 TypeScript 是 JavaScript 的超集。TypeScript 增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript，然后交给浏览器或其他 JavaScript 运行环境执行。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"3\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 的主要作用是为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。类型声明文件是 TypeScript 中的一种特殊文件，通常以 .d.ts 作为扩展名。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"2\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 中的数据类型包括 JavaScript 中的所有类型，以及六个新类型：any、unknown、never、void、tuple、enum。此外，TypeScript 还提供了两种用于自定义类型的方式：type 和 interface。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"9\\\"}],[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 的代码量通常要大于 JavaScript，但由于 TypeScript 的代码结构更加清晰，在后期代码的维护中 TypeScript 却胜于 JavaScript。</p>\\\\n\\\"},{\\\"type\\', 0, NULL, '2025-07-21 01:22:28', 95);
