INSERT INTO `sys_oper_log` VALUES (843, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"ts是啥\",\"createBy\":\"admin\",\"createTime\":\"2025-07-23 12:54:45\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"知识库中未找到您要的答案！\",\"createBy\":\"admin\",\"createTime\":\"2025-07-23 12:54:45\",\"messageId\":\"\",\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>知识库中未找到您要的答案！</p>\\\\n\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":3,\\\"chunks\\\":[{\\\"id\\\":\\\"8ddfc15802d8d7a3\\\",\\\"content\\\":\\\"ts是什么\\\",\\\"document_id\\\":\\\"a8be0e8a5b0311f087cc0242ac120006\\\",\\\"document_name\\\":\\\"aaa.txt\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"\\\",\\\"positions\\\":[[1,0,0,0,0]],\\\"url\\\":null,\\\"similarity\\\":0.5870671089307359,\\\"vector_similarity\\\":0.9771158355884482,\\\"term_similarity\\\":0.001994018944167497,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"8d214717c0bb8eb0\\\",\\\"content\\\":\\\"ts是什么\\\",\\\"document_id\\\":\\\"f83c46e85b0311f0918b0242ac120006\\\",\\\"document_name\\\":\\\"aaa(1).txt\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"\\\",\\\"positions\\\":[[1,0,0,0,0]],\\\"url\\\":null,\\\"similarity\\\":0.5870671089307359,\\\"vector_similarity\\\":0.9771158355884482,\\\"term_similarity\\\":0.001994018944167497,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"8c34d62cf2eaf706\\\",\\\"content\\\":\\\"ts是什么\\\\nThe image shows a text-based conversation with Chinese characters. It appears to be a screenshot from an electronic device such as a smartphone or computer. The background is plain white, and there\'s no other distinctive visual information provided by the image. There are no visible numbers in the text.\\\",\\\"document_id\\\":\\\"362ff5c65b0411f09fc60242ac120006\\\",\\\"document_name\\\":\\\"11.png\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-8c34d62cf2eaf706\\\",\\\"positions\\\":[],\\\"url\\\":null,\\\"similarity\\\":0.4160647268617565,\\\"vector_similarity\\\":0.6921118654734825,\\\"term_similarity\\\":0.001994018944167497,\\\"doc_type\\\":\\\"image\\', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 15:48:46\",\"id\":242,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript是什么\",\"createBy\":\"system\",\"createTime\":\"2025-07-10 17:08:55\",\"id\":258,\"params\":{},\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"system\",\"createTime\":\"2025-07-10 17:08:55\",\"id\":259,\"packageContent\":\"[[{\\\"type\\\":\\\"txt\\\",\\\"value\\\":\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。</p>\\\\n\\\"},{\\\"type\\\":\\\"btn\\\",\\\"value\\\":\\\"2\\\"}]]\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.9123333734653447,\\\"vector_similarity\\\":0.7077779115511492,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. Typ', 0, NULL, '2025-07-23 04:54:45', 97);
