INSERT INTO `sys_oper_log` VALUES (871, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript是什么语言\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:37\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"w9qsoqffogssgn5v2hq0gebbawxzkroj\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是一种由微软开发的编程语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##1$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:37\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是一种由微软开发的编程语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":9,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.49397283779354056,\\\"vector_similarity\\\":0.6855964049024121,\\\"term_similarity\\\":0.20653748713023323,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"6c41097425be7f71\\\",\\\"content\\\":\\\"tianyetianyutianyu⼋、泛型tianya九、类型声明⽂件⼀、TypeScript 简介tianyuotiany1. TypeScript 由微软开发，是基于JavaScript 的⼀个扩展语⾔。2. TypeScript 包含了JavaScript 的所有内容，即：TypeScript 是JavaScript 的超集。的开发。4. TypeScript 需要编译为JavaS', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:36\",\"id\":313,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"w9qsoqffogssgn5v2hq0gebbawxzkroj\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript是什么语言\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:38\",\"id\":314,\"params\":{},\"role\":\"user\",\"sessionId\":\"w9qsoqffogssgn5v2hq0gebbawxzkroj\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是一种由微软开发的编程语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##1$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:38\",\"id\":315,\"packageContent\":\"\\\"<p>TypeScript 是一种由微软开发的编程语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":9,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.49397283779354056,\\\"vector_similarity\\\":0.6855964049024121,\\\"term_similarity\\\":0.20653748713023323,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"6c41097425be7f71\\\",\\\"content\\\":\\\"tianyetianyutianyu⼋、泛', 0, NULL, '2025-07-24 07:46:38', 95);
INSERT INTO `sys_oper_log` VALUES (872, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"请详细介绍一下typescript\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:49:47\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"w9qsoqffogssgn5v2hq0gebbawxzkroj\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript，然后交给浏览器或其他 JavaScript 运行环境执行。##4$$\\n\\nTypeScript 的主要特点包括：\\n1. **静态类型检查**：TypeScript 在编译时进行类型检查，可以在开发阶段发现并修复类型错误，提高代码的健壮性。##1$$\\n2. **接口（Interface）**：TypeScript 提供了接口的概念，用于定义对象的形状，确保对象具有特定的属性和方法。##0$$\\n3. **泛型（Generics）**：TypeScript 支持泛型，可以在编写代码时使用类型参数，提高代码的复用性和灵活性。##4$$\\n4. **类型声明文件**：TypeScript 中的类型声明文件（通常以 `.d.ts` 作为扩展名）为现有的 JavaScript 代码提供类型信息，使得 TypeScript 能够在使用这些 JavaScript 库或模块时进行类型检查和提示。##2$$\\n\\nTypeScript 中的数据类型包括：\\n1. JavaScript 中的所有数据类型。\\n2. 六个新类型：`any`、`unknown`、`never`、`void`、`tuple`、`enum`。##8$$\\n3. 两种用于自定义类型的方式：`type` 和 `interface`。##8$$\\n\\nTypeScript 的代码量通常比 JavaScript 大，但由于其代码结构更加清晰，在后期代码的维护中 TypeScript 却胜于 JavaScript。##5$$\\n\\n总的来说，TypeScript 通过增加静态类型检查、接口、泛型等特性，使得代码更加健壮、可维护，适合大型项目的开发。##1$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:49:47\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript，然后交给浏览器或其他 JavaScript 运行环境执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span></p>\\\\n<p>TypeScript 的主要特点包括：</p>\\\\n<ol>\\\\n<li><strong>静态类型检查</strong>：TypeScript 在编译时进行类型检查，可以在开发阶段发现并修复类型错误，提高代码的健壮性。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span></li>\\\\n<li><strong>接口（Interface）</strong>：TypeScript 提供了接口的概念，用于定义对象的形状，确保对象具有特定的属性和方法。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"0\\\\\\\"></span></li>\\\\n<li><strong>泛型（Generics）</strong>：TypeScript 支持泛型，可以在编写代码时使用类型参数，提高代码的复用性和灵活性。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span></li>\\\\n<li><st', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:36\",\"id\":313,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"w9qsoqffogssgn5v2hq0gebbawxzkroj\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript是什么语言\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:38\",\"id\":314,\"params\":{},\"role\":\"user\",\"sessionId\":\"w9qsoqffogssgn5v2hq0gebbawxzkroj\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是一种由微软开发的编程语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##1$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 15:46:38\",\"id\":315,\"packageContent\":\"\\\"<p>TypeScript 是一种由微软开发的编程语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":9,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.49397283779354056,\\\"vector_similarity\\\":0.6855964049024121,\\\"term_similarity\\\":0.20653748713023323,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"6c41097425be7f71\\\",\\\"content\\\":\\\"tianyetianyutianyu⼋、泛', 0, NULL, '2025-07-24 07:49:47', 97);
