INSERT INTO `sys_oper_log` VALUES (878, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript 是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:26:42\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:26:42\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":60,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.8374921199095137,\\\"vector_similarity\\\":0.7291535331825227,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的Ja', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 15:48:46\",\"id\":242,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript 是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:26:43\",\"id\":318,\"params\":{},\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:26:43\",\"id\":319,\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目的开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":60,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.8374921199095137,\\\"vector_similarity\\\":0.7291535331825227,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScr', 0, NULL, '2025-07-24 08:26:42', 80);
