INSERT INTO `sys_oper_log` VALUES (880, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript 是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:10\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:10\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":60,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.8374921199095137,\\\"vector_similarity\\\":0.7291535331825227,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的Ja', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 15:48:46\",\"id\":242,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript 是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:11\",\"id\":320,\"params\":{},\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:11\",\"id\":321,\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":60,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.8374921199095137,\\\"vector_similarity\\\":0.7291535331825227,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScr', 0, NULL, '2025-07-24 08:27:10', 78);
INSERT INTO `sys_oper_log` VALUES (881, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"请详细介绍一下 javascript\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:35\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"知识库中未找到您要的答案！\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:35\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>知识库中未找到您要的答案！</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":5,\\\"chunks\\\":[{\\\"id\\\":\\\"0743ced61125cada\\\",\\\"content\\\":\\\"2. ⾃动装箱：JavaScript 在必要时会⾃动将原始类型包装成对象，以便调⽤⽅法或访问属性tianyutianyuotianya//原始类型字符串let str =\'hello\';tianyy//当访问str.length时，JavaScript引擎做了以下⼯作：let size =(function(){//1. ⾃动装箱：创建⼀个临时的String对象包装原始字符串let tempStringObject =new String(str);\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-0743ced61125cada\\\",\\\"positions\\\":[[8,86,536,499,533],[9,86,536,45,75],[9,84,534,91,150]],\\\"url\\\":null,\\\"similarity\\\":0.4474882856346361,\\\"vector_similarity\\\":0.5763417195209191,\\\"term_similarity\\\":0.25420813480521165,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"03068b931b4272dd\\\",\\\"content\\\":\\\"tianyo//赋值合法person ={name:\'张三\'age:18,gender:\'男\'声明函数类型iamylet count: (a: number, b: number)=>numbercount =function (x, y){return x +y备注：●TypeScript 中的=>在函数类型声明时表示函数类型，描述其参数类型和返回类型。●JavaScript 中的=>是⼀种定义函数的语法，是具体的函数实现。●函数类型声明还可以使⽤：接⼝、⾃定义类型等⽅式，下⽂中会详细讲解。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-03068b931b4272dd\\\",\\\"positions\\\":[[17,104,545,582,658],[18,88,529,74,85],[18,83,524,105,132],[18,86,527,202,283]],\\\"url\\\":null,\\\"similarity\\\":0.43735530182795157,\\\"vector_similarity\\\":0.4418060408077469,\\\"term_similarity\\\":0.43067919335825866,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"d829b50e3710c53e\\\",\\\"content\\\":\\\"tianytlet', '[{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-07-10 15:48:46\",\"id\":242,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"typescript 是什么\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:11\",\"id\":320,\"params\":{},\"role\":\"user\",\"sessionId\":\"3mthh5h9e07ydgfhrtttd5uq01y8hyqn\"},{\"chatId\":\"b1bce6885af311f093f00242ac120006\",\"content\":\"TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。##2$$\",\"createBy\":\"admin\",\"createTime\":\"2025-07-24 16:27:11\",\"id\":321,\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种基于 JavaScript 的扩展语言，它是 JavaScript 的超集，包含了 JavaScript 的所有内容，并增加了静态类型检查、接口、泛型等现代开发特性，更适合大型项目开发。TypeScript 需要编译为 JavaScript 后才能在浏览器或其他 JavaScript 运行环境中执行。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":60,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.8374921199095137,\\\"vector_similarity\\\":0.7291535331825227,\\\"term_similarity\\\":1,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScr', 0, NULL, '2025-07-24 08:27:35', 78);
