 ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.4397287775791739,\\\"vector_similarity\\\":0.5094913710148115,\\\"term_similarity\\\":0.33508488742571757,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"6c41097425be7f71\\\",\\\"content\\\":\\\"tianyetianyutianyu⼋、泛型tianya九、类型声明⽂件', 0, NULL, '2025-07-31 14:06:10', 66);
