INSERT INTO `sys_oper_log` VALUES (942, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '117.129.46.211', 'XX XX', '[{\"chatId\":\"2e89c0346e5c11f093a20242ac120003\",\"content\":\"T2000火警控制器是哪个公司的\",\"createBy\":\"admin\",\"createTime\":\"2025-08-01 06:45:01\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"7zs0svqup7sljsrf30vdiepcr9xiz4ur\"},{\"chatId\":\"2e89c0346e5c11f093a20242ac120003\",\"content\":\"\\n**ERROR**: Error code: 400 - {\'error\': {\'message\': \'Invalid top_p value, the valid range of top_p is (0, 1.0]\', \'type\': \'invalid_request_error\', \'param\': None, \'code\': \'invalid_request_error\'}}\",\"createBy\":\"admin\",\"createTime\":\"2025-08-01 06:45:01\",\"messageId\":\"\",\"packageContent\":\"\\\"<p><strong>ERROR</strong>: Error code: 400 - {\'error\': {\'message\': \'Invalid top_p value, the valid range of top_p is (0, 1.0]\', \'type\': \'invalid_request_error\', \'param\': None, \'code\': \'invalid_request_error\'}}</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"9084a782225fecd1\\\",\\\"content\\\":\\\"2.2.1 火警窗口在正常状态下，火警窗口显示产品名字、日期/时间、和公司名字。当一个火警信号出现时，火警窗口将显示“第一个火警（FIRST FIRE）”和相关的信息（如回路、地址、位置等信息）；如果有多个火警出现，火警窗口将显示第一个火警和最后一个火警信号的信息。系统收到的火警总数将显示在火警窗口第5 行的右边。2.2.2 状态窗口状态窗口显示系统内故障总数、隔离总数等信息。2.2.3 主窗口主窗口显示系统的历史记录、信息字符、菜单和设备型号。2.2.4 软键窗口软键窗口的显示信息会随着可选功能的变化而变化。2.3 正常操作当控制器通电初始化完成后，如果系统中没有故障和火警、控制钥匙处在“普通（0）”位置，屏幕显示应如图6所示。2.3.1 事件监控本系统中的事件是指系统的状态发生了变化，这个变化必须要操作者响应，同时也可产生输出信号。典型的事件包括如下（但不局限于这些事件）：•主电源故障；•探测到火警； •按了控制器前面板上的“火警(FIRE ALARM)”键。所有的事件都需要操作者做出相应的响应，响应方式由事件的性质决定。各种事件的优先级如下： •火警；•预报警；•故障；•隔离；•测试模式；•警告；•信息。系统发生过的事件都会储存在系统的事件记录里，事件记录可以以两种格式显示：\\\",\\\"document_id\\\":\\\"4e69e37458a511f0b36e0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"e5f12ce058a311f0bfdc0242ac120006\\\",\\\"image_id\\\":\\\"e5f12ce058a311f0bfdc0242ac120006-9084a782225fecd1\\\",\\\"positions\\\":[[10,86,540,175,186],[10,106,560,192,203],[10,86,541,208,236],[10,107,561,240,252],[10,86,540,456,468],[10,106,560,472,484],[10,86,541,507,516],[10,106,560,522,534],[10,85,539,555,567],[10,105,559,571,583],[10,86,541,621,650],[10,86,540,671,683],[10,106,560,687,715],[10,105,559,718,731],[11,105,560,289,301],[11,10', '[{\"chatId\":\"2e89c0346e5c11f093a20242ac120003\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-08-01 06:38:04\",\"id\":376,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"7zs0svqup7sljsrf30vdiepcr9xiz4ur\"},{\"chatId\":\"2e89c0346e5c11f093a20242ac120003\",\"content\":\"于T2000火警控制器\",\"createBy\":\"admin\",\"createTime\":\"2025-08-01 06:38:06\",\"id\":377,\"params\":{},\"role\":\"user\",\"sessionId\":\"7zs0svqup7sljsrf30vdiepcr9xiz4ur\"},{\"chatId\":\"2e89c0346e5c11f093a20242ac120003\",\"content\":\"\\n**ERROR**: Error code: 400 - {\'error\': {\'message\': \'Invalid top_p value, the valid range of top_p is (0, 1.0]\', \'type\': \'invalid_request_error\', \'param\': None, \'code\': \'invalid_request_error\'}}\",\"createBy\":\"admin\",\"createTime\":\"2025-08-01 06:38:06\",\"id\":378,\"packageContent\":\"\\\"<p><strong>ERROR</strong>: Error code: 400 - {\'error\': {\'message\': \'Invalid top_p value, the valid range of top_p is (0, 1.0]\', \'type\': \'invalid_request_error\', \'param\': None, \'code\': \'invalid_request_error\'}}</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"e5e0b827eadaa16a\\\",\\\"content\\\":\\\"警告在进行任何T2000火警探测和报警系统操作前，请仔细阅读本手册的有关内容T2000数字寻址式火警探测和报警系统操作手册目录1. 总则1.1 简介1.2 T2000系统的主要性能和功能2. 操作指导2.1 面板显示和控制 3 2.1.1 总则 3 2.1.2 操作显示模块 3 2.1.3 操作控制模块 5 2.2 液晶显示器 6 2.2.1 火警窗口 7 2.2.2 状态窗口 7 2.2.3 主窗口 7 2.2.4 软键窗口 7 2.3 正常操作 7 2.3.1 事件监控 7 2.3.2 事件显示 8 2.4 发生火警时的操作 8 2.4.1 系统响应 9 2.4.2 报警器消声 10 2.4.3 控制器复位 10 2.4.4 多个事件 11 2.4.5 预报警警告 11 2.5 发生故障时的操作 112.5.1 系统反应2.5.2 故障处理 12 2.6 火警控制键 12 2.6.1 火警键 12 2.6.2 白天/夜晚方式键 13 2.6.3 检查延迟键 13 2.6.4 测试键 13 2.7 辅助显示设备 13 2.7.1 总则 13 2.7.2 复示器 14 2.7.3 打印机 14 11 3. 控制器功能3.1 登陆级别 14 3.2 输入和更改密码 15 3.2.1 输入密码 15 3.2.2 更改密码 16 3.3 有效值 163.4 主菜单3.5 查看状态 17\\\",\\\"document_id\\\":\\\"4e69e37458a511f0b36e0242ac120006\\\",\\\"document_name\\\":\\\"T2000中文操作手册.pdf\\\",\\\"dataset_id\\\":\\\"e5f12ce058a311f0bfdc0242ac120006\\\",\\\"image_id\\\":\\\"e5f12ce058a311f0bfdc0242ac120006-e5e0b827eadaa16a\\\",\\\"positions\\\":[[1,96,502,105,117],[1,141,547,228,260],[1,113,519,289,324],[2,87,493,103,150],[2,86,492,168,63', 0, NULL, '2025-07-31 22:45:01', 110);
