INSERT INTO `sys_oper_log` VALUES (1074, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/session', '122.139.63.162', 'XX XX', '{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:43\",\"id\":96,\"params\":{},\"sessionId\":\"u62xmyrhk0xvwaesbm3xmavmfki0aou9\",\"sessionName\":\"typescript是哪个厂商出的语言\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:43\",\"id\":96,\"params\":{},\"sessionId\":\"u62xmyrhk0xvwaesbm3xmavmfki0aou9\",\"sessionName\":\"typescript是哪个厂商出的语言\"}}', 0, NULL, '2025-08-05 01:21:44', 335);
INSERT INTO `sys_oper_log` VALUES (1075, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"content\":\"typescript是哪个厂商出的语言\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:49\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"u62xmyrhk0xvwaesbm3xmavmfki0aou9\"},{\"content\":\"TypeScript 是由微软（Microsoft）开发的语言##5$$。它是基于 JavaScript 的一个扩展，包含了 JavaScript 的所有内容，并且添加了静态类型检查、接口、泛型等现代开发特性，使得它更适合大型项目的开发。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:49\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软（Microsoft）开发的语言<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"5\\\\\\\"></span>。它是基于 JavaScript 的一个扩展，包含了 JavaScript 的所有内容，并且添加了静态类型检查、接口、泛型等现代开发特性，使得它更适合大型项目的开发。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":25,\\\"chunks\\\":[{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-62cc88e82cf42ccb\\\",\\\"positions\\\":[[2,56,555,328,342],[2,70,568,391,406],[2,50,548,444,464],[2,47,545,493,510],[2,65,564,541,711]],\\\"url\\\":null,\\\"similarity\\\":0.33977787025909467,\\\"vector_similarity\\\":0.5429020563851152,\\\"term_similarity\\\":0.2527246476336573,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"679f437aaa84a3eb\\\",\\\"content\\\":\\\"let d =-99 //TypeScript会推断出变量d的类型是数字d =false //警告：不能将类型“boolean”分配给类型“number”但要注意，类型推断不是万能的，⾯对复杂类型时推断容易出问题，所以尽量还是明确的编写类型声明！六、类型总览tianyJavaScript 中的数据类型①string ②number ③boolean ④null ⑤undefined ⑥bigint ⑦symbol ⑧object\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-679f437aaa84a3', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:44\",\"id\":495,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"u62xmyrhk0xvwaesbm3xmavmfki0aou9\"},{\"content\":\"typescript是哪个厂商出的语言\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:49\",\"id\":496,\"params\":{},\"role\":\"user\",\"sessionId\":\"u62xmyrhk0xvwaesbm3xmavmfki0aou9\"},{\"content\":\"TypeScript 是由微软（Microsoft）开发的语言##5$$。它是基于 JavaScript 的一个扩展，包含了 JavaScript 的所有内容，并且添加了静态类型检查、接口、泛型等现代开发特性，使得它更适合大型项目的开发。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-05 09:21:49\",\"id\":497,\"packageContent\":\"\\\"<p>TypeScript 是由微软（Microsoft）开发的语言<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"5\\\\\\\"></span>。它是基于 JavaScript 的一个扩展，包含了 JavaScript 的所有内容，并且添加了静态类型检查、接口、泛型等现代开发特性，使得它更适合大型项目的开发。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":25,\\\"chunks\\\":[{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-62cc88e82cf42ccb\\\",\\\"positions\\\":[[2,56,555,328,342],[2,70,568,391,406],[2,50,548,444,464],[2,47,545,493,510],[2,65,564,541,711]],\\\"url\\\":null,\\\"similarity\\\":0.33977787025909467,\\\"vector_similarity\\\":0.5429020563851152,\\\"term_similarity\\\":0.2527246476336573,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"679f437aaa84a3eb\\\",\\\"content\\\":\\\"let d =-99 //TypeScript会推断出变量d的类型是数字d =false //警告：不能将类型“boolean”分配给类型“number”但要注意，类型推断不是万能的，⾯对复杂类型时推断容易出问题，所以尽量还是明确的编写类型声明！六、类型总览tianyJavaScript 中的数据类型①string ②number ③boolean ④null ⑤undefined ⑥bigint ⑦symbol ⑧object\\\",\\\"document_id\\\":\\\"ce84eddc58a611f0', 0, NULL, '2025-08-05 01:21:49', 142);
