INSERT INTO `sys_oper_log` VALUES (1105, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'test1', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript是哪个厂商出的\",\"createBy\":\"test1\",\"createTime\":\"2025-08-05 16:00:07\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"u62xmyrhk0xvwaesbm3xmavmfki0aou9\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 是由微软（Microsoft）开发的##6$$。它是JavaScript的一个超集，为JavaScript添加了静态类型检查等特性，使得代码更适合大型项目的开发。\",\"createBy\":\"test1\",\"createTime\":\"2025-08-05 16:00:07\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软（Microsoft）开发的<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"6\\\\\\\"></span>。它是JavaScript的一个超集，为JavaScript添加了静态类型检查等特性，使得代码更适合大型项目的开发。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":62,\\\"chunks\\\":[{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-62cc88e82cf42ccb\\\",\\\"positions\\\":[[2,56,555,328,342],[2,70,568,391,406],[2,50,548,444,464],[2,47,545,493,510],[2,65,564,541,711]],\\\"url\\\":null,\\\"similarity\\\":0.4070463841338725,\\\"vector_similarity\\\":0.5306040332047912,\\\"term_similarity\\\":0.3540931059606216,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"679f437aaa84a3eb\\\",\\\"content\\\":\\\"let d =-99 //TypeScript会推