b7858a611f090a30242ac120006-62cc88e82cf42ccb\\\",\\\"positions\\\":[[2,56,555,328,342],[2,70,568,391,406],[2,50,548,444,464],[2,47,545,493,510],[2,65,564,541,711]],\\\"url\\\":null,\\\"similarity\\\":0.4070463841338725,\\\"vector_similarity\\\":0.5306040332047912,\\\"term_similarity\\\":0.3540931059606216,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"679f437aaa84a3eb\\\",\\\"content\\\":\\\"let d =-99 //TypeScript会推断出变量d的类型是数字d =false //警告：不能将类型“boolean”分配给类型“number”但要注意，类型推断不是万能的，⾯对复杂类型时推断容易出问题，所以尽量还是明确的编写类型声明！六、类型总览tianyJavaScript 中的数据类型①string ②number ③boolean ④null ⑤undefined ⑥bigint ⑦symbol ⑧object\\\",\\\"d', 0, NULL, '2025-08-05 08:00:07', 105);
