INSERT INTO `sys_oper_log` VALUES (1114, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'test1', '研发部门1', '/aftersales/session', '122.139.63.162', 'XX XX', '{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:11\",\"id\":106,\"params\":{},\"sessionId\":\"mmi1tof0mdvju1zbfl2mkvtwk042skmc\",\"sessionName\":\"typescript是啥\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:11\",\"id\":106,\"params\":{},\"sessionId\":\"mmi1tof0mdvju1zbfl2mkvtwk042skmc\",\"sessionName\":\"typescript是啥\"}}', 0, NULL, '2025-08-06 00:53:11', 162);
INSERT INTO `sys_oper_log` VALUES (1115, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'test1', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript是啥\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:19\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"mmi1tof0mdvju1zbfl2mkvtwk042skmc\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 是由微软开发的一种编程语言，它是 JavaScript 的一个超集，这意味着它包含了 JavaScript 的所有内容并在此基础上添加了额外的特性##2$$。TypeScript 主要增加了静态类型检查、接口、泛型等现代开发特性，这些特性使得它更适合于大型项目的开发##1$$。由于 TypeScript 代码结构清晰，尽管在编写时代码量可能比 JavaScript 稍多，但在后期维护中具有明显优势##4$$。\\n\\nTypeScript 代码不能直接在浏览器中运行，需要先编译成 JavaScript 代码，然后才能由浏览器的解析器执行##4$$。这种编译过程可以通过命令行或自动化编译来完成##5$$。\\n\\n此外，TypeScript 还使用类型声明文件（通常以 .d.ts 作为扩展名），为现有的 JavaScript 代码提供类型信息，以便在 TypeScript 项目中进行类型检查和提示##3$$。\\n\\n以上信息来自知识库，希望能解答您的问题。如果需要更多详细信息，请继续提问。\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:19\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种编程语言，它是 JavaScript 的一个超集，这意味着它包含了 JavaScript 的所有内容并在此基础上添加了额外的特性<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。TypeScript 主要增加了静态类型检查、接口、泛型等现代开发特性，这些特性使得它更适合于大型项目的开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span>。由于 TypeScript 代码结构清晰，尽管在编写时代码量可能比 JavaScript 稍多，但在后期维护中具有明显优势<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。</p>\\\\n<p>TypeScript 代码不能直接在浏览器中运行，需要先编译成 JavaScript 代码，然后才能由浏览器的解析器执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。这种编译过程可以通过命令行或自动化编译来完成<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"5\\\\\\\"></span>。</p>\\\\n<p>此外，TypeScript 还使用类型声明文件（通常以 .d.ts 作为扩展名），为现有的 JavaScript 代码提供类型信息，以便在 TypeScript 项目中进行类型检查和提示<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"3\\\\\\\"></span>。</p>\\\\n<p>以上信息来自知识库，希望能解答您的问题。如果需要更多详细信息，请继续提问。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u000', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:11\",\"id\":541,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"mmi1tof0mdvju1zbfl2mkvtwk042skmc\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript是啥\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:20\",\"id\":542,\"params\":{},\"role\":\"user\",\"sessionId\":\"mmi1tof0mdvju1zbfl2mkvtwk042skmc\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 是由微软开发的一种编程语言，它是 JavaScript 的一个超集，这意味着它包含了 JavaScript 的所有内容并在此基础上添加了额外的特性##2$$。TypeScript 主要增加了静态类型检查、接口、泛型等现代开发特性，这些特性使得它更适合于大型项目的开发##1$$。由于 TypeScript 代码结构清晰，尽管在编写时代码量可能比 JavaScript 稍多，但在后期维护中具有明显优势##4$$。\\n\\nTypeScript 代码不能直接在浏览器中运行，需要先编译成 JavaScript 代码，然后才能由浏览器的解析器执行##4$$。这种编译过程可以通过命令行或自动化编译来完成##5$$。\\n\\n此外，TypeScript 还使用类型声明文件（通常以 .d.ts 作为扩展名），为现有的 JavaScript 代码提供类型信息，以便在 TypeScript 项目中进行类型检查和提示##3$$。\\n\\n以上信息来自知识库，希望能解答您的问题。如果需要更多详细信息，请继续提问。\",\"createBy\":\"test1\",\"createTime\":\"2025-08-06 08:53:20\",\"id\":543,\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种编程语言，它是 JavaScript 的一个超集，这意味着它包含了 JavaScript 的所有内容并在此基础上添加了额外的特性<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。TypeScript 主要增加了静态类型检查、接口、泛型等现代开发特性，这些特性使得它更适合于大型项目的开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span>。由于 TypeScript 代码结构清晰，尽管在编写时代码量可能比 JavaScript 稍多，但在后期维护中具有明显优势<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。</p>\\\\n<p>TypeScript 代码不能直接在浏览器中运行，需要先编译成 JavaScript 代码，然后才能由浏览器的解析器执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。这种编译过程可以通过命令行或自动化编译来完成<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"5\\\\\\\"></span>。</p>\\\\n<p>此外，TypeScript 还使用类型声明文件（通常以 .d.ts 作为扩展名），为现有的 JavaScript 代码提供类型信息，以便在 TypeScript 项目中进行类型检查和提示<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"3\\\\\\\"></span>。</p>\\\\n<p>以上信息来自知识库，希望能解答您的问题。如果需要更多详细信息，请继续提问。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScri', 0, NULL, '2025-08-06 00:53:19', 110);
INSERT INTO `sys_oper_log` VALUES (1116, 'session', 1, 'com.gaisoft.kb.controller.KbSessionController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/session', '192.168.1.101', '内网IP', '{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 08:59:49\",\"id\":107,\"params\":{},\"sessionId\":\"6tfvseq4dh0j9u2koonfgnustfykdxfi\",\"sessionName\":\"typescript中文简介\"}', '{\"msg\":\"创建成功\",\"code\":200,\"data\":{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 08:59:49\",\"id\":107,\"params\":{},\"sessionId\":\"6tfvseq4dh0j9u2koonfgnustfykdxfi\",\"sessionName\":\"typescript中文简介\"}}', 0, NULL, '2025-08-06 00:59:48', 254);
INSERT INTO `sys_oper_log` VALUES (1117, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '192.168.1.101', '内网IP', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript中文简介\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:00:01\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"6tfvseq4dh0j9u2koonfgnustfykdxfi\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 是由微软开发的一种编程语言，它是JavaScript的一个超集##1$$。TypeScript不仅包含了JavaScript的所有内容，还添加了一些额外的特性，如静态类型检查、接口、泛型等，这些特性使得TypeScript更适合于大型项目的开发##2$$。由于TypeScript是JavaScript的超集，因此它的代码需要编译成JavaScript才能在浏览器或其他JavaScript运行环境中执行##4$$。\\n\\nTypeScript的主要特点包括：\\n1. 静态类型检查：TypeScript提供了静态类型检查，这有助于在编码阶段捕捉到错误，提高代码质量。\\n2. 接口：接口用于定义对象的结构，使得代码更易于理解和维护。\\n3. 泛型：泛型用于创建可重用的组件，这样一个组件可以支持多种类型的数据。\\n4. 其他类型和语法：TypeScript引入了如any、unknown、never、void、object、tuple、enum、type等类型，以及一些特殊的语法糖，如属性的简写形式等##6$$##7$$。\\n\\n需要注意的是，虽然TypeScript的代码量可能比JavaScript大，但由于其代码结构更清晰，因此在后期代码维护方面具有优势##4$$。\\n\\n知识库中未找到您要的答案！如果您需要更多关于TypeScript的信息，请提供更具体的问题。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:00:01\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种编程语言，它是JavaScript的一个超集<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span>。TypeScript不仅包含了JavaScript的所有内容，还添加了一些额外的特性，如静态类型检查、接口、泛型等，这些特性使得TypeScript更适合于大型项目的开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。由于TypeScript是JavaScript的超集，因此它的代码需要编译成JavaScript才能在浏览器或其他JavaScript运行环境中执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。</p>\\\\n<p>TypeScript的主要特点包括：</p>\\\\n<ol>\\\\n<li>静态类型检查：TypeScript提供了静态类型检查，这有助于在编码阶段捕捉到错误，提高代码质量。</li>\\\\n<li>接口：接口用于定义对象的结构，使得代码更易于理解和维护。</li>\\\\n<li>泛型：泛型用于创建可重用的组件，这样一个组件可以支持多种类型的数据。</li>\\\\n<li>其他类型和语法：TypeScript引入了如any、unknown、never、void、object、tuple、enum、type等类型，以及一些特殊的语法糖，如属性的简写形式等<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"6\\\\\\\"></span><span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"7\\\\\\\"></span>。</li>\\\\n</ol>\\\\n<p>需要注意的是，虽然TypeScript的代码量可能比JavaScript大，但由于其代码结构更清晰，因此在后期代码维护方面具有优势<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。</p>\\\\n<p>知识库中未找到您要的答案！如果您需要更多关于Type', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 08:59:50\",\"id\":544,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"6tfvseq4dh0j9u2koonfgnustfykdxfi\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript中文简介\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:00:01\",\"id\":545,\"params\":{},\"role\":\"user\",\"sessionId\":\"6tfvseq4dh0j9u2koonfgnustfykdxfi\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 是由微软开发的一种编程语言，它是JavaScript的一个超集##1$$。TypeScript不仅包含了JavaScript的所有内容，还添加了一些额外的特性，如静态类型检查、接口、泛型等，这些特性使得TypeScript更适合于大型项目的开发##2$$。由于TypeScript是JavaScript的超集，因此它的代码需要编译成JavaScript才能在浏览器或其他JavaScript运行环境中执行##4$$。\\n\\nTypeScript的主要特点包括：\\n1. 静态类型检查：TypeScript提供了静态类型检查，这有助于在编码阶段捕捉到错误，提高代码质量。\\n2. 接口：接口用于定义对象的结构，使得代码更易于理解和维护。\\n3. 泛型：泛型用于创建可重用的组件，这样一个组件可以支持多种类型的数据。\\n4. 其他类型和语法：TypeScript引入了如any、unknown、never、void、object、tuple、enum、type等类型，以及一些特殊的语法糖，如属性的简写形式等##6$$##7$$。\\n\\n需要注意的是，虽然TypeScript的代码量可能比JavaScript大，但由于其代码结构更清晰，因此在后期代码维护方面具有优势##4$$。\\n\\n知识库中未找到您要的答案！如果您需要更多关于TypeScript的信息，请提供更具体的问题。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:00:01\",\"id\":546,\"packageContent\":\"\\\"<p>TypeScript 是由微软开发的一种编程语言，它是JavaScript的一个超集<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"1\\\\\\\"></span>。TypeScript不仅包含了JavaScript的所有内容，还添加了一些额外的特性，如静态类型检查、接口、泛型等，这些特性使得TypeScript更适合于大型项目的开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。由于TypeScript是JavaScript的超集，因此它的代码需要编译成JavaScript才能在浏览器或其他JavaScript运行环境中执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"4\\\\\\\"></span>。</p>\\\\n<p>TypeScript的主要特点包括：</p>\\\\n<ol>\\\\n<li>静态类型检查：TypeScript提供了静态类型检查，这有助于在编码阶段捕捉到错误，提高代码质量。</li>\\\\n<li>接口：接口用于定义对象的结构，使得代码更易于理解和维护。</li>\\\\n<li>泛型：泛型用于创建可重用的组件，这样一个组件可以支持多种类型的数据。</li>\\\\n<li>其他类型和语法：TypeScript引入了如any、unknown、never、void、object、tuple、enum、type等类型，以及一些特殊的语法糖，如属性的简写形式等<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"6\\\\\\\"></span><span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"7\\\\\\\"></span>。</li>\\\\n</o', 0, NULL, '2025-08-06 01:00:00', 156);
