INSERT INTO `sys_oper_log` VALUES (1125, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript有啥优势\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:34\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"sf6gyj2xva2fq7ezp7vscdvmhwl2pwjn\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 增加了许多现代开发特性，如静态类型检查、接口、泛型等，这些特性使其更适合大型项目开发##0$$。相较于 JavaScript，TypeScript 的代码结构更加清晰，虽然在功能相同的情况下代码量可能大于 JavaScript，但在后期代码维护中具有明显优势##2$$。此外，TypeScript 是 JavaScript 的超集，包含了 JavaScript 的所有内容，并通过编译器将 TypeScript 代码转换为 JavaScript 代码，以便在浏览器或其他 JavaScript 运行环境中执行##6$$。这些特点使得 TypeScript 在大型应用开发中能够提供更好的开发体验和维护效率。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:34\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 增加了许多现代开发特性，如静态类型检查、接口、泛型等，这些特性使其更适合大型项目开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"0\\\\\\\"></span>。相较于 JavaScript，TypeScript 的代码结构更加清晰，虽然在功能相同的情况下代码量可能大于 JavaScript，但在后期代码维护中具有明显优势<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。此外，TypeScript 是 JavaScript 的超集，包含了 JavaScript 的所有内容，并通过编译器将 TypeScript 代码转换为 JavaScript 代码，以便在浏览器或其他 JavaScript 运行环境中执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"6\\\\\\\"></span>。这些特点使得 TypeScript 在大型应用开发中能够提供更好的开发体验和维护效率。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-62cc88e82cf42ccb\\\",\\\"positions\\\":[[2,56,555,328,342],[2,70,568,391,406],[2,50,548,444,464],[2,47,545,493,510],[2,65,564,541,711]],\\\"url\\\":null,\\\"similarity', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:28\",\"id\":555,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"sf6gyj2xva2fq7ezp7vscdvmhwl2pwjn\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript有啥优势\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:35\",\"id\":556,\"params\":{},\"role\":\"user\",\"sessionId\":\"sf6gyj2xva2fq7ezp7vscdvmhwl2pwjn\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 增加了许多现代开发特性，如静态类型检查、接口、泛型等，这些特性使其更适合大型项目开发##0$$。相较于 JavaScript，TypeScript 的代码结构更加清晰，虽然在功能相同的情况下代码量可能大于 JavaScript，但在后期代码维护中具有明显优势##2$$。此外，TypeScript 是 JavaScript 的超集，包含了 JavaScript 的所有内容，并通过编译器将 TypeScript 代码转换为 JavaScript 代码，以便在浏览器或其他 JavaScript 运行环境中执行##6$$。这些特点使得 TypeScript 在大型应用开发中能够提供更好的开发体验和维护效率。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:35\",\"id\":557,\"packageContent\":\"\\\"<p>TypeScript 增加了许多现代开发特性，如静态类型检查、接口、泛型等，这些特性使其更适合大型项目开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"0\\\\\\\"></span>。相较于 JavaScript，TypeScript 的代码结构更加清晰，虽然在功能相同的情况下代码量可能大于 JavaScript，但在后期代码维护中具有明显优势<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。此外，TypeScript 是 JavaScript 的超集，包含了 JavaScript 的所有内容，并通过编译器将 TypeScript 代码转换为 JavaScript 代码，以便在浏览器或其他 JavaScript 运行环境中执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"6\\\\\\\"></span>。这些特点使得 TypeScript 在大型应用开发中能够提供更好的开发体验和维护效率。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a61', 0, NULL, '2025-08-06 01:07:35', 127);
INSERT INTO `sys_oper_log` VALUES (1126, '聊天记录同步', 1, 'com.gaisoft.kb.controller.KbChatController.add()', 'POST', 1, 'admin', '研发部门1', '/aftersales/chat', '122.139.63.162', 'XX XX', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript是哪个厂商发明的语言\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:59\",\"messageId\":\"\",\"packageContent\":\"\",\"params\":{},\"reference\":\"\",\"role\":\"user\",\"sessionId\":\"sf6gyj2xva2fq7ezp7vscdvmhwl2pwjn\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 是由微软（Microsoft）发明的语言。##2$$\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:59\",\"messageId\":\"\",\"packageContent\":\"\\\"<p>TypeScript 是由微软（Microsoft）发明的语言。<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span></p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":27,\\\"chunks\\\":[{\\\"id\\\":\\\"29b0302cada2afad\\\",\\\"content\\\":\\\"TypeScript 快速上⼿⼀、TypeScript 简介tiany三、编译TypeScript\\\\u0000. 命令⾏编译\\\\u0000. ⾃动化编译四、类型声明五、类型推断六、类型总览七、常⽤类型与语法\\\\u0000. any \\\\u0000. unknown \\\\u0000. never \\\\u0000. void \\\\u0000. object \\\\u0000. tuple \\\\u0000. enum \\\\u0000. type\\\\u0000. ⼀个特殊情况\\\\u0000\\\\u0000. 复习类相关知识\\\\u0000\\\\u0000. 属性修饰符\\\\u0000\\\\u0000. 抽象类\\\\u0000\\\\u0000. interface（接⼝）\\\\u0000\\\\u0000. ⼀些相似概念的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与type 的区别\\\\u0000\\\\u0000.\\\\u0000. interface 与抽象类的区别\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a611f090a30242ac120006-29b0302cada2afad\\\",\\\"positions\\\":[[1,49,263,57,82],[1,54,269,115,129],[1,43,257,160,667]],\\\"url\\\":null,\\\"similarity\\\":0.25143807043891686,\\\"vector_similarity\\\":0.567587626260055,\\\"term_similarity\\\":0.11594540365842909,\\\"doc_type\\\":\\\"\\\"},{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"datase', '[{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"你好！ 我是你的助理，有什么可以帮到你的吗？\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:28\",\"id\":555,\"params\":{},\"role\":\"assistant\",\"sessionId\":\"sf6gyj2xva2fq7ezp7vscdvmhwl2pwjn\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"typescript有啥优势\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:35\",\"id\":556,\"params\":{},\"role\":\"user\",\"sessionId\":\"sf6gyj2xva2fq7ezp7vscdvmhwl2pwjn\"},{\"chatId\":\"1b036bf46e7611f0b8900242ac120003\",\"content\":\"TypeScript 增加了许多现代开发特性，如静态类型检查、接口、泛型等，这些特性使其更适合大型项目开发##0$$。相较于 JavaScript，TypeScript 的代码结构更加清晰，虽然在功能相同的情况下代码量可能大于 JavaScript，但在后期代码维护中具有明显优势##2$$。此外，TypeScript 是 JavaScript 的超集，包含了 JavaScript 的所有内容，并通过编译器将 TypeScript 代码转换为 JavaScript 代码，以便在浏览器或其他 JavaScript 运行环境中执行##6$$。这些特点使得 TypeScript 在大型应用开发中能够提供更好的开发体验和维护效率。\",\"createBy\":\"admin\",\"createTime\":\"2025-08-06 09:07:35\",\"id\":557,\"packageContent\":\"\\\"<p>TypeScript 增加了许多现代开发特性，如静态类型检查、接口、泛型等，这些特性使其更适合大型项目开发<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"0\\\\\\\"></span>。相较于 JavaScript，TypeScript 的代码结构更加清晰，虽然在功能相同的情况下代码量可能大于 JavaScript，但在后期代码维护中具有明显优势<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"2\\\\\\\"></span>。此外，TypeScript 是 JavaScript 的超集，包含了 JavaScript 的所有内容，并通过编译器将 TypeScript 代码转换为 JavaScript 代码，以便在浏览器或其他 JavaScript 运行环境中执行<span class=\\\\\\\"popover-placeholder\\\\\\\" data-id=\\\\\\\"6\\\\\\\"></span>。这些特点使得 TypeScript 在大型应用开发中能够提供更好的开发体验和维护效率。</p>\\\\n\\\"\",\"params\":{},\"reference\":\"{\\\"total\\\":64,\\\"chunks\\\":[{\\\"id\\\":\\\"62cc88e82cf42ccb\\\",\\\"content\\\":\\\"3. TypeScript 增加了：静态类型检查、接⼝、泛型等很多现代开发特性，更适合⼤型项⽬Lian境执⾏。⼆、为何需要TypeScript\\\\u0000今⾮昔⽐的JavaScript（了解）tiany●JavaScript 当年诞⽣时的定位是浏览器脚本语⾔，⽤于在⽹⻚中嵌⼊简单的逻辑，且代码量很少。●随着时间的推移，JavaScript 变得越来越流⾏，如今的JavaScript 已经可以全栈编程了。●现如今的JavaScript 应⽤场景⽐当年丰富的多，代码量也⽐当年⼤很多，随便⼀个JavaScript 项⽬的代码量，可以轻松的达到⼏万⾏，甚⾄⼗⼏万⾏！●然⽽JavaScript 当年“出⽣简陋”，没考虑到如今的应⽤场景和代码量，逐渐就出现了很多困扰。\\\",\\\"document_id\\\":\\\"ce84eddc58a611f080b00242ac120006\\\",\\\"document_name\\\":\\\"TypeScript 快速上手.pdf\\\",\\\"dataset_id\\\":\\\"b7c45b7858a611f090a30242ac120006\\\",\\\"image_id\\\":\\\"b7c45b7858a61', 0, NULL, '2025-08-06 01:07:59', 126);
